// ─── SCHOOL DIRECTORY (mock, for the searchable school picker) ──────────────
// Mock list of selectable schools, each tagged with its type so SchoolSelect
// can filter to just high schools or just colleges once the student has
// already told us which one they are -- typing "Univ" while set to
// "highschool" no longer surfaces "University of Michigan". Exactly two
// entries (DEMO_SCHOOL_COLLEGE, DEMO_SCHOOL_HS — see the institutional demo
// section) are wired to real mock class data; every other entry here is just
// a selectable name with no further behavior.
const SCHOOL_DIRECTORY=[
  {name:"Harvard University",type:"college"},{name:"Lincoln High School",type:"highschool"},
  {name:"Stanford University",type:"college"},{name:"New York University",type:"college"},
  {name:"UC Berkeley",type:"college"},{name:"UCLA",type:"college"},
  {name:"MIT",type:"college"},{name:"Lehigh University",type:"college"},
  {name:"University of Michigan",type:"college"},{name:"Ohio State University",type:"college"},
  {name:"Georgia Tech",type:"college"},{name:"Boston University",type:"college"},
  {name:"Roosevelt High School",type:"highschool"},{name:"Jefferson High School",type:"highschool"},
  {name:"Central High School",type:"highschool"},{name:"Riverside High School",type:"highschool"},
  {name:"Franklin High School",type:"highschool"},{name:"University of Texas at Austin",type:"college"},
  {name:"Penn State University",type:"college"},{name:"Arizona State University",type:"college"},
  {name:"Northwestern University",type:"college"},{name:"Washington High School",type:"highschool"},
  {name:"University of Florida",type:"college"},{name:"Miami Dade College",type:"college"},
];
// Searchable school picker — type-to-filter + click-to-select, same shape as
// the friend-search pattern used in Studlin Network (text input + filtered
// list). Typing always calls onChange immediately, so a school that isn't in
// the mock directory is never blocked — the "fallback" is structural, not a
// separate confirm step, which matters since most real students' schools
// won't be in this small demo list. statusFilter ("highschool"/"college"),
// when passed, restricts matches to that type; omit it to search everything.
const SchoolSelect=({value,onChange,placeholder,theme,statusFilter,onCommit})=>{
  const [q,setQ]=useState(value||"");
  const [open,setOpen]=useState(false);
  const [liveMatches,setLiveMatches]=useState([]); // [{name,type}] from the shared cross-user schools directory
  useEffect(()=>{setQ(value||"");},[value]);
  // Live results from every student who's ever picked/typed a school
  // before, not just this hardcoded seed list -- debounced the same way
  // the friend search already debounces its own Firestore queries
  // (see runQuery), `active` discards a stale response if a newer query
  // started before this one resolved. Only a single-field range query on
  // nameLower -- filtering by statusFilter happens client-side below
  // rather than as a second `where` clause, so this never needs a
  // Firestore composite index to be deployed for it to work.
  useEffect(()=>{
    const term=q.trim().toLowerCase();
    if(!term){setLiveMatches([]);return;}
    let active=true;
    const t=setTimeout(()=>{
      fsdb().collection('schools').where('nameLower','>=',term).where('nameLower','<=',term+"").limit(15).get()
        .then(snap=>{if(active)setLiveMatches(snap.docs.map(d=>d.data()));})
        .catch(()=>{if(active)setLiveMatches([]);});
    },250);
    return()=>{active=false;clearTimeout(t);};
  },[q]);
  const pool=statusFilter?SCHOOL_DIRECTORY.filter(s=>s.type===statusFilter):SCHOOL_DIRECTORY;
  const localMatches=q.trim()?pool.filter(s=>s.name.toLowerCase().includes(q.toLowerCase())).map(s=>s.name):[];
  const liveNames=(statusFilter?liveMatches.filter(s=>s.type===statusFilter):liveMatches).map(s=>s.name);
  // Live (real, cross-user) results first, seed list fills in behind them,
  // deduped case-insensitively -- the seed list is what keeps the two demo
  // schools (and a zero-latency first paint) available even before any
  // real student has added them to the shared directory.
  const seenNames=new Set();
  const matches=[...liveNames,...localMatches].filter(name=>{
    const key=name.toLowerCase();
    if(seenNames.has(key))return false;
    seenNames.add(key);
    return true;
  }).slice(0,6);
  const th=theme||{bg:T.card2,border:T.border,text:T.text,muted:T.muted};
  const pick=(name)=>{setQ(name);onChange(name);setOpen(false);};
  return (
    <div style={{position:"relative"}}>
      <input
        value={q}
        onChange={e=>{setQ(e.target.value);onChange(e.target.value);setOpen(true);}}
        onFocus={()=>setOpen(true)}
        onBlur={()=>{
          // Fires once when the student is actually done editing (whether
          // they picked a suggestion or typed something brand new) --
          // never on every keystroke, which is what makes this safe to use
          // as the trigger for adding a new school to the shared directory.
          if(onCommit&&q.trim())onCommit(q.trim());
          setTimeout(()=>setOpen(false),150);
        }}
        placeholder={placeholder||"Search or type your school"}
        style={{width:"100%",background:th.bg,border:`1px solid ${th.border}`,borderRadius:8,padding:"10px 12px",color:th.text,fontSize:13.5,fontFamily:T.font,outline:"none",boxSizing:"border-box"}}
      />
      {open&&q.trim()&&(
        <div style={{position:"absolute",top:"calc(100% + 4px)",left:0,right:0,zIndex:20,background:th.bg,border:`1px solid ${th.border}`,borderRadius:8,overflow:"hidden",boxShadow:"0 12px 28px -12px rgba(0,0,0,0.35)"}}>
          {matches.length>0
            ? matches.map(name=>(
                <div key={name} onMouseDown={e=>e.preventDefault()} onClick={()=>pick(name)} style={{padding:"9px 12px",fontSize:13,color:th.text,cursor:"pointer",borderBottom:`1px solid ${th.border}`}}>{name}</div>
              ))
            : <div onMouseDown={e=>e.preventDefault()} onClick={()=>setOpen(false)} style={{padding:"9px 12px",fontSize:12.5,color:th.muted,cursor:"pointer"}}>Can't find your school? Use "{q}" instead</div>
          }
        </div>
      )}
    </div>
  );
};

// Single swatch button that opens a color grid on click, instead of showing
// every option inline at once — picking a color closes the dropdown, and the
// caller is expected to tint the subject's own row with it (see subjectRowStyle)
// so the color choice reads immediately without a separate legend.
const ColorSelect=({value,onChange})=>{
  const [open,setOpen]=useState(false);
  return (
    <div style={{position:"relative",flexShrink:0}}>
      <button type="button" onClick={()=>setOpen(o=>!o)} onBlur={()=>setTimeout(()=>setOpen(false),150)}
        title="Choose a color" style={{width:26,height:26,borderRadius:"50%",background:value,border:`2px solid ${T.white}30`,cursor:"pointer",padding:0,flexShrink:0}} />
      {open&&(
        <div style={{position:"absolute",top:"calc(100% + 6px)",left:0,zIndex:30,background:T.card,border:`1px solid ${T.border}`,borderRadius:10,padding:10,display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:8,boxShadow:"0 12px 28px -12px rgba(0,0,0,0.5)"}}>
          {SUBJECT_COLORS.map(c=>(
            <div key={c} onMouseDown={e=>e.preventDefault()} onClick={()=>{onChange(c);setOpen(false);}} title={c}
              style={{width:20,height:20,borderRadius:"50%",background:c,cursor:"pointer",border:value===c?`2.5px solid ${T.white}`:"2px solid transparent",boxSizing:"border-box",transform:value===c?"scale(1.15)":"scale(1)",transition:"transform 0.12s"}} />
          ))}
        </div>
      )}
    </div>
  );
};
const subjectRowStyle=(color)=>({display:"flex",alignItems:"center",gap:10,padding:"10px 12px",borderRadius:10,background:color+"14",border:`1px solid ${color}33`,borderLeft:`3px solid ${color}`});

