// Starts a new chain: places the first probe session via findReliableSlotFor.
// No separate "parent" record — this session IS the task, linked to its
// eventual follow-ups only by attackChainId, same idiom as split-session
// tasks link via splitGroup/splitIndex/splitTotal.
function startAttackBlockChain(fields,events,routines,prefs,desiredDate,desiredTime){
  const chainId="attack-"+Date.now()+"-"+Math.random().toString(36).slice(2,7);
  const probeMins=fields.probeMins||ATTACK_BLOCK_DEFAULT_PROBE_MINS;
  const slot=findReliableSlotFor(events,routines,prefs,desiredDate,desiredTime,probeMins,fields.deadline||null,fields.difficulty);
  if(!slot)return null; // no legal slot before the deadline -- nothing to start a chain with
  return {
    id:String(Date.now()+Math.random()*1000),
    title:fields.title,date:slot.date,time:slot.time,
    subject:fields.subject||"",notes:fields.notes||"",kind:"study block",duration:probeMins,
    priority:fields.priority??500,difficulty:fields.difficulty??500,
    deadline:fields.deadline||null,status:"pending",timeSpent:0,completedAt:null,
    isAttackBlock:true,attackChainId:chainId,attackIndex:1,
    placementReason:slot.reason||null,
    ...(fields.noteId?{noteId:fields.noteId}:{}),
    // dueEventId links this chain back to the plain due-date marker it was
    // generated from (e.g. a syllabus-scanned assignment) — lets a single
    // "cancel prep sessions for this" action on the due-date event find and
    // remove every session in the chain, not just this first one.
    ...(fields.dueEventId?{dueEventId:fields.dueEventId}:{}),
  };
}
// Wraps startAttackBlockChain with phase awareness — shared by every place
// a deadline item's first prep session gets scheduled (commitSyllabusEvents'
// immediate path, the daily sweep's "auto" mode, and the "ask" mode accept
// handler all call this instead of startAttackBlockChain directly), so the
// phase-tagging logic exists exactly once. When `phases` is a non-empty
// array, the resulting chain represents phase 0 only — its title becomes
// "<project title>: <phase name>" so the calendar shows which slice of the
// project this session actually is, and projectPhaseIndex/phaseName/
// projectTitle ride along on the returned task for the phase-advance logic
// (see advanceProjectPhase) to find once this session is marked truly done.
function startPhaseAwareAttackChain(fields,phases,events,routines,prefs,desiredDate,desiredTime){
  const hasPhases=Array.isArray(phases)&&phases.length>0;
  const task=startAttackBlockChain(hasPhases?{...fields,title:fields.title+": "+phases[0]}:fields,events,routines,prefs,desiredDate,desiredTime);
  if(!task)return null;
  return hasPhases?{...task,projectPhaseIndex:0,phaseName:phases[0],projectTitle:fields.title}:task;
}
// Add/Edit Task's own entry point for starting an Attack Block on an
// Assignment or Project -- unlike commitSyllabusEvents' path (which always
// builds a due-date marker first, then a chain linked to it via
// dueEventId), Add/Edit Task used to call startPhaseAwareAttackChain
// directly and commit just the bare chain task. Two real consequences of
// that gap: a phased Project's `phases` list was never actually stored
// anywhere (only phase 0's name survived, baked into the task's title),
// so advanceProjectPhase -- which requires completedTask.dueEventId to
// resolve to a marker with a real `phases` array -- silently no-opped
// the moment phase 0 finished, and the project stopped there forever;
// and neither an Attack-Block Assignment nor Project ever became
// kind:"deadline", so Dashboard's Assignments/Projects master lists
// (which filter on exactly that) never saw them. This builds the marker
// first (same shape buildSyllabusEventBatch's own markers use) and the
// chain task second, dueEventId-linked back to it, closing both gaps at
// once. `markerId` is the caller's choice deliberately -- Add Task always
// mints a fresh id (a brand new marker), Edit Task's retroactive path
// passes the existing event's own id so the event effectively becomes
// its own marker in place rather than leaving an orphaned duplicate
// around. Returns null (same as startAttackBlockChain) when no legal
// slot exists for the chain at all -- the caller decides how to surface
// that, same "no open slot" toast every other Attack Block entry point
// already shows.
function buildAssignmentAttackBlockPair(markerId,fields,phases,events,routines,prefs,desiredDate,desiredTime){
  const marker={
    id:markerId,title:fields.title,date:fields.deadline||desiredDate,time:"23:59",
    subject:fields.subject||"",notes:fields.notes||"",kind:"deadline",
    priority:fields.priority??500,difficulty:fields.difficulty??500,
    deadline:fields.deadline||null,duration:null,status:"pending",timeSpent:0,completedAt:null,
    ...(phases.length>0?{phases:phases.map((name,pi)=>({name,status:pi===0?"active":"pending"}))}:{}),
  };
  const task=startPhaseAwareAttackChain({...fields,dueEventId:marker.id},phases,events.concat([marker]),routines,prefs,desiredDate,desiredTime);
  if(!task)return null;
  return {marker,task};
}
// Called when a phased Attack Block session is marked genuinely finished
// (TaskTimerModal's "Yes, I'm finished" -> onAttackBlockFinish), never on
// an extended/follow-up session — extending just means "still on this same
// phase." A no-op (returns the same `events` reference) for anything that
// isn't part of a phased project: an ordinary Attack Block chain has no
// projectPhaseIndex, and completedTask.dueEventId not resolving to a
// marker with a real phases array covers a manually-deleted or malformed
// due-date event without throwing.
// No gate delay for the next phase, unlike the very first phase — the
// project is already underway, there's no "is this too early to start"
// question left to ask, so its probe gets scheduled starting today exactly
// the way the first phase's would have once its own gate opened.
function advanceProjectPhase(completedTask,events,routines,prefs,todayKey){
  if(!completedTask||completedTask.projectPhaseIndex===undefined||!completedTask.dueEventId)return events;
  const marker=events.find(e=>e.id===completedTask.dueEventId);
  if(!marker||!Array.isArray(marker.phases))return events;
  const curIdx=completedTask.projectPhaseIndex;
  if(!marker.phases[curIdx])return events;
  const nextIdx=curIdx+1;
  const hasNext=nextIdx<marker.phases.length;
  const updatedPhases=marker.phases.map((p,pi)=>{
    if(pi===curIdx)return {...p,status:"done"};
    if(pi===nextIdx&&hasNext)return {...p,status:"active"};
    return p;
  });
  const updatedMarker={...marker,phases:updatedPhases};
  let working=events.map(e=>e.id===marker.id?updatedMarker:e);
  if(hasNext){
    const nextTask=startAttackBlockChain({
      title:marker.title+": "+marker.phases[nextIdx].name,
      deadline:marker.deadline,priority:marker.priority,difficulty:marker.difficulty,
      noteId:marker.noteId,dueEventId:marker.id,
    },working,routines,prefs,todayKey||dayKey(),prefs.workStartTime);
    working=working.concat([{...nextTask,projectPhaseIndex:nextIdx,phaseName:marker.phases[nextIdx].name,projectTitle:marker.title}]);
  }
  return working;
}
// How many days out each follow-up chunk should target, given N chunks and
// a runway of days until the finish-by buffer. A square-root ease: the
// FIRST gap (today -> chunk 2) is the largest -- exactly when a deadline
// weeks out doesn't feel urgent yet, so a bigger nudge forward matters more
// -- and later gaps compress as the deadline approaches, syncing with the
// natural push to finish that shows up on its own by then. Back-weighted,
// not evenly spaced and not front-crammed. Falls back to tight day-by-day
// packing (today, today+1, ...) when there's no deadline to ramp toward, or
// the runway doesn't even have room for one chunk per day -- spreading thin
// chunks over a fat runway helps; spreading fat chunks over a thin one just
// delays necessary work for no reason.
const ATTACK_BLOCK_RAMP_EXPONENT=0.5;
function computeAttackBlockRampOffsets(chunkCount,runwayDays){
  if(chunkCount<=1)return [0];
  // <= not < -- at exactly one day per chunk there's no room left to ramp
  // (the sqrt curve's rounding can even collide and overflow past the
  // runway when it's this tight), so tight packing is correct here too,
  // not just when the runway is strictly shorter than the chunk count.
  if(!runwayDays||runwayDays<=chunkCount)return Array.from({length:chunkCount},(_,i)=>i);
  const offsets=Array.from({length:chunkCount},(_,i)=>{
    const t=i/(chunkCount-1);
    return Math.round(Math.pow(t,ATTACK_BLOCK_RAMP_EXPONENT)*(runwayDays-1));
  });
  for(let i=1;i<offsets.length;i++){
    if(offsets[i]<=offsets[i-1])offsets[i]=offsets[i-1]+1;
  }
  // The forward pass above can push a rounding collision past the runway
  // on a tight-but-not-tight-enough-to-fall-back runway (e.g. 5 chunks
  // over 6 days) -- pull everything back inside bounds from the end while
  // keeping it strictly increasing. Always possible here: the fallback
  // above already guarantees chunkCount < runwayDays, i.e. room for at
  // least one integer day per chunk.
  if(offsets[offsets.length-1]>runwayDays-1){
    offsets[offsets.length-1]=runwayDays-1;
    for(let i=offsets.length-2;i>=0;i--){
      if(offsets[i]>=offsets[i+1])offsets[i]=offsets[i+1]-1;
    }
  }
  return offsets;
}
// Schedules the next session in an existing chain once the student's
// self-reported % (via TaskTimerModal's attackCheckIn phase) has produced a
// recommended nextMins. Sibling to scheduleAssignmentExtension, not an
// extension of it — that function's semantics (assignmentId copied onto
// every chunk) are Canvas-assignment-specific. Uses findReliableSlotFor
// (this session's reliability-aware placement), unlike
// scheduleAssignmentExtension which predates that engine.
function scheduleAttackBlockFollowUp(task,nextMins){
  const events=lsGet("events",[]);
  const routines=getWeeklyRoutine();
  const prefs=getSchedulePreferences();
  const CHUNK=90;
  const chunks=[];
  let remaining=Math.max(5,nextMins);
  while(remaining>0){const c=Math.min(CHUNK,remaining);chunks.push(c);remaining-=c;}
  const today=dayKey();
  let runwayDays=null;
  if(task.deadline){
    const finishByD=new Date(task.deadline+"T12:00:00");finishByD.setDate(finishByD.getDate()-ATTACK_BLOCK_FINISH_BUFFER_DAYS);
    const days=Math.ceil((finishByD-new Date(today+"T12:00:00"))/86400000);
    if(days>0)runwayDays=days;
  }
  const dayOffsets=computeAttackBlockRampOffsets(chunks.length,runwayDays);
  let cursorDate=today;
  const newEvents=[];
  for(let i=0;i<chunks.length;i++){
    const m=chunks[i];
    const target=new Date(today+"T12:00:00");target.setDate(target.getDate()+dayOffsets[i]);
    const targetKey=dayKey(target);
    // The ramp offset is a target, never a demotion -- a later chunk can
    // never be scheduled before an earlier one just because its own ramp
    // slot came out earlier than where the previous chunk actually landed
    // (e.g. that day was full and findReliableSlotFor bumped it forward).
    const searchFrom=targetKey>cursorDate?targetKey:cursorDate;
    const slot=findReliableSlotFor(events.concat(newEvents),routines,prefs,searchFrom,prefs.workStartTime,m,task.deadline||null,task.difficulty);
    // No legal slot left anywhere -- stop here and keep whatever chunks
    // already placed rather than fabricating a double-booked one.
    if(!slot)break;
    newEvents.push({
      id:String(Date.now()+i)+"-ab-"+i,
      title:task.title,date:slot.date,time:slot.time,
      subject:task.subject,notes:task.notes||"",kind:"study block",duration:m,
      priority:task.priority,difficulty:task.difficulty,
      status:"pending",timeSpent:0,completedAt:null,deadline:task.deadline||null,
      isAttackBlock:true,attackChainId:task.attackChainId,attackIndex:(task.attackIndex||1)+1+i,
      placementReason:slot.reason||null,
      // Carries the chain's dueEventId forward so every follow-up stays
      // findable by a single "all sessions linked to this due date" query,
      // not just the chain's first session (see the cancel-all action on
      // the due-date event's edit modal).
      ...(task.dueEventId?{dueEventId:task.dueEventId}:{}),
      // Same carry-forward for phase tagging -- without this, a phase that
      // needed a follow-up session (not finished on the first probe alone)
      // would silently break advanceProjectPhase the moment "Yes, I'm
      // finished" fires on THIS chunk instead of the original probe: no
      // projectPhaseIndex on the completed task means no next phase ever
      // gets scheduled.
      ...(task.projectPhaseIndex!==undefined?{projectPhaseIndex:task.projectPhaseIndex,phaseName:task.phaseName,projectTitle:task.projectTitle}:{}),
    });
    const d=new Date(slot.date+"T12:00:00");d.setDate(d.getDate()+1);
    cursorDate=dayKey(d);
  }
  lsSet("events",events.concat(newEvents));
}
// "Re-optimize" (Dashboard's Assignments master list) -- a chain's
// remaining pending minutes get pulled off the calendar and rescheduled
// fresh via scheduleAttackBlockFollowUp, the same real placement engine
// every other follow-up round already uses. Never touches sessions already
// marked done (their real logged time stays exactly where it happened),
// and is a genuine no-op (returns false) when there's nothing pending to
// move, rather than silently doing nothing with no signal why.
function reoptimizeAttackChain(chainId){
  const events=lsGet("events",[]);
  const chainPending=events.filter(e=>e.attackChainId===chainId&&e.status==="pending");
  if(chainPending.length===0)return false;
  const totalMins=chainPending.reduce((s,e)=>s+(e.duration||0),0);
  const template=chainPending[0];
  const withoutPending=events.filter(e=>!(e.attackChainId===chainId&&e.status==="pending"));
  lsSet("events",withoutPending);
  scheduleAttackBlockFollowUp(template,totalMins);
  return true;
}
// Needs-attention detection — a standalone signal, deliberately separate
// from the ask-mode prep digest above (that's about assignments not yet
// STARTED; this is about ones already IN PROGRESS whose real pace turned
// out slower than the original estimate). Sums each chain's currently
// pending (not yet done) scheduled minutes and compares that against what
// can still realistically fit before its deadline at the same sustainable
// pace the start-date gate itself backward-schedules from
// (ATTACK_BLOCK_SUSTAINABLE_WEEKLY_MINS) — if the pending work no longer
// fits, cramming isn't the honest answer, restructuring the week is.
function detectAttackBlockOverruns(events,todayKey){
  const today=todayKey||dayKey();
  const chains={};
  events.forEach(ev=>{
    if(!ev.isAttackBlock||!ev.attackChainId)return;
    if(!chains[ev.attackChainId])chains[ev.attackChainId]={title:ev.title,deadline:ev.deadline||null,pendingMins:0};
    if(ev.deadline)chains[ev.attackChainId].deadline=ev.deadline;
    if(ev.status!=="done")chains[ev.attackChainId].pendingMins+=(ev.duration||0);
  });
  const overruns=[];
  Object.keys(chains).forEach(chainId=>{
    const c=chains[chainId];
    if(c.pendingMins<=0||!c.deadline)return;
    const finishByD=new Date(c.deadline+"T12:00:00");finishByD.setDate(finishByD.getDate()-ATTACK_BLOCK_FINISH_BUFFER_DAYS);
    const runwayDays=Math.ceil((finishByD-new Date(today+"T12:00:00"))/86400000);
    const capacityMins=Math.max(0,runwayDays)*(ATTACK_BLOCK_SUSTAINABLE_WEEKLY_MINS/7);
    if(c.pendingMins>capacityMins){
      overruns.push({chainId,title:c.title,deadline:c.deadline,pendingMins:c.pendingMins,capacityMins:Math.round(capacityMins),runwayDays});
    }
  });
  return overruns;
}
// Dismiss-until-tomorrow, not a multi-day cooldown like the other
// suggestion nudges — this is a live deadline-risk signal, not a "settings
// might be slightly off" one, so silencing it for days would work against
// the whole point of surfacing it. Reappears on its own the next day if
// the underlying chain is (still) genuinely over capacity; keyed per-chain
// so dismissing one overrun doesn't hide a different, unrelated one.
function getAttackOverrunDismissals(){return lsGet("attackOverrunDismissals",{});}
function isAttackOverrunDismissedToday(chainId){return getAttackOverrunDismissals()[chainId]===dayKey();}
function dismissAttackOverrunToday(chainId){
  const d=getAttackOverrunDismissals();
  d[chainId]=dayKey();
  lsSet("attackOverrunDismissals",d);
}
// Dev-only demo seeder for the (mocked, Coming Soon) Canvas connector —
// creates one course + a few assignments in Firestore, then generates each
// assignment's first "Attack Block" via the same gap-finder real Canvas sync
// would use, so the estimation-engine loop is fully demoable without a real
// Canvas integration. Gated behind DEV_MODE, triggered from Settings >
// Integrations.
async function injectMockCanvasData(){
  const uid=firebase.auth().currentUser?.uid;
  if(!uid)return;
  const now=new Date().toISOString();
  const courseRef=await fsdb().collection('courses').add({
    userId:uid,name:"AP Chemistry",code:"CHEM 301",color:"#7BACDF",source:"mock",createdAt:now,updatedAt:now,
  });
  const mockAssignments=[
    {title:"Problem Set 4: Thermodynamics",daysOut:2},
    {title:"Lab Report: Titration Curves",daysOut:4},
    {title:"Reading Response: Ch. 9",daysOut:6},
  ];
  const events=lsGet("events",[]),routines=getWeeklyRoutine(),prefs=getSchedulePreferences();
  const newEvents=[];
  for(const a of mockAssignments){
    const deadline=new Date();deadline.setDate(deadline.getDate()+a.daysOut);
    const deadlineKey=dayKey(deadline);
    const asgRef=await fsdb().collection('assignments').add({
      userId:uid,courseId:courseRef.id,courseName:"AP Chemistry",title:a.title,
      canvasDeadline:deadline.toISOString(),estimatedMinutes:60,status:"pending",source:"mock",
      createdAt:now,updatedAt:now,
    });
    const attackDate=new Date(deadline);attackDate.setHours(attackDate.getHours()-48);
    const desiredDate=dayKey(attackDate<new Date()?new Date():attackDate);
    const slot=findOpenSlotFor(events.concat(newEvents),routines,prefs,desiredDate,prefs.workStartTime,60,deadlineKey);
    newEvents.push({
      id:String(Date.now())+"-"+Math.random().toString(36).slice(2,7),
      title:"Attack Block: "+a.title,date:slot.date,time:slot.time,
      subject:"Chemistry",kind:"study block",duration:60,
      assignmentId:asgRef.id,isAttackBlock:true,status:"pending",deadline:deadlineKey,
    });
  }
  lsSet("events",events.concat(newEvents));
}
// Subtracts a list of {start,end} "holes" out of a single {start,end} base
// interval, returning the remaining segments — used to punch free-period
// gaps through the WeeklyPlanner's School Hours background tint.
function subtractIntervals(base,holes){
  let segments=[{...base}];
  (holes||[]).forEach(h=>{
    segments=segments.flatMap(seg=>{
      if(h.end<=seg.start||h.start>=seg.end)return [seg];
      const out=[];
      if(h.start>seg.start)out.push({start:seg.start,end:Math.min(h.start,seg.end)});
      if(h.end<seg.end)out.push({start:Math.max(h.end,seg.start),end:seg.end});
      return out;
    });
  });
  return segments.filter(s=>s.end>s.start);
}
const prioLabel=(v)=>{const p=v/10;return p<=20?"Low":p<=40?"Low–Medium":p<=60?"Medium":p<=80?"High":"Urgent";};
const diffLabel=(v)=>{const p=v/10;return p<=20?"Very Easy":p<=40?"Easy":p<=60?"Medium":p<=80?"Hard":"Very Hard";};
async function getAuthToken(){try{const u=firebase.auth().currentUser;if(!u)return null;return await u.getIdToken();}catch(e){return null;}}
async function authFetch(url,opts={}){try{const token=await getAuthToken();const h=Object.assign({},opts.headers||{});if(token)h["Authorization"]="Bearer "+token;return fetch(url,Object.assign({},opts,{headers:h}));}catch(e){return fetch(url,opts);}}
async function fetchUserProfile(){try{const res=await authFetch("/api/me");if(!res.ok)return null;const d=await res.json();lsSet("credits",d.credits);lsSet("plan",d.plan||"Free");["stripeSubscriptionId","subscriptionStatus","subscriptionInterval","subscriptionCancelAtPeriodEnd","subscriptionCurrentPeriodEnd","subscriptionEndsAt"].forEach(k=>lsSet(k,d[k]===undefined?null:d[k]));
  // "onboarded" otherwise lives only in this browser's localStorage, so a
  // fresh browser/Incognito window/device makes an already-onboarded account
  // repeat the wizard. Only ever upgrades false->true here, never the
  // reverse — a slow/failed write to this same flag elsewhere shouldn't be
  // able to un-onboard someone mid-session.
  if(d.onboarded)lsSet("onboarded",true);
  return d;}catch(e){return null;}}

// ─── FIRESTORE (client SDK) — live user directory + friend graph ────────────
// Everything privacy-sensitive (credits, plan, email) stays server-only via
// the existing /api/* routes + Admin SDK. This client SDK is used only for
// the public directory (`profiles`) and the `friendships` relationship graph,
// per firestore.rules.
const fsdb=()=>firebase.firestore();
// Every accepted-friend uid, both directions -- mirrors the two-query
// pattern FriendsChat already uses for its own friends list (friendships
// docs have no deterministic id, so there's no single query that covers
// both "I sent" and "they sent").
async function getAcceptedFriendUids(myUid){
  const [a,b]=await Promise.all([
    fsdb().collection('friendships').where('senderId','==',myUid).where('status','==','accepted').get(),
    fsdb().collection('friendships').where('receiverId','==',myUid).where('status','==','accepted').get(),
  ]);
  const uids=new Set();
  a.docs.forEach(d=>uids.add(d.data().receiverId));
  b.docs.forEach(d=>uids.add(d.data().senderId));
  return [...uids];
}
// Publishes this student's own busy-time-only intervals (see
// computeBusyWindowsPayload) so an opted-in friend's "Find Shared Study
// Window" search can see real availability instead of guessing — never
// event titles, never anyone but current accepted friends (sharedWithUids
// is exactly what firestore.rules checks on read). Silently no-ops if the
// opt-in setting is off, so any call site can call this unconditionally
// without checking the setting itself first. Recomputes the friend list
// fresh on every call rather than trusting a stale cache, since a friend
// removed since the last publish must stop being able to read this.
async function publishBusyWindows(){
  if(!lsGet("settings",{}).shareAvailability)return;
  const myUid=firebase.auth().currentUser?.uid;
  if(!myUid)return;
  try{
    const sharedWithUids=await getAcceptedFriendUids(myUid);
    const intervals=computeBusyWindowsPayload(lsGet("events",[]),getWeeklyRoutine(),getSchedulePreferences(),dayKey());
    await fsdb().collection('busyWindows').doc(myUid).set({ownerUid:myUid,sharedWithUids,intervals,updatedAt:new Date().toISOString()});
  }catch(e){}
}
// Withdraws consent immediately (toggling the setting off) rather than
// leaving a stale, no-longer-authorized copy of this student's busy times
// sitting in Firestore until it happens to get overwritten.
async function unpublishBusyWindows(){
  const myUid=firebase.auth().currentUser?.uid;
  if(!myUid)return;
  try{await fsdb().collection('busyWindows').doc(myUid).delete();}catch(e){}
}
// Reads whichever of `otherUids` have opted in AND currently share with
// this signed-in user. A permission-denied read (not shared with us) or a
// missing doc (never opted in) both resolve to "no extra data for this
// person" — findSharedStudyWindow degrades to its old own-calendar-only
// behavior for that participant, never surfaces an error over a feature
// that was always optional. Returns a Map date -> [{s,e}], merged across
// every contributing participant.
async function fetchFriendsBusyIntervals(otherUids){
  const byDate=new Map();
  await Promise.all(otherUids.map(async(uid)=>{
    try{
      const doc=await fsdb().collection('busyWindows').doc(uid).get();
      if(!doc.exists)return;
      const data=doc.data();
      (data.intervals||[]).forEach(iv=>{
        if(!byDate.has(iv.date))byDate.set(iv.date,[]);
        byDate.get(iv.date).push({s:iv.s,e:iv.e});
      });
    }catch(e){/* not shared with us, or offline -- degrade gracefully */}
  }));
  return byDate;
}
const slugUsername=(name)=>(name||"").toLowerCase().replace(/[^a-z0-9]/g,"").slice(0,24)||"student";
// Creates/refreshes this user's public directory entry so they're searchable
// and their name/school stay current. Safe to call anytime a signed-in user
// is present — merges rather than overwrites, and never touches private data.
async function upsertProfile(extra={}){
  const u=firebase.auth().currentUser;
  if(!u)return;
  const prof=getProfile();
  const name=u.displayName||prof.name||"Student";
  const username=prof.username||slugUsername(name);
  const school=extra.school!==undefined?extra.school:(prof.affiliation||prof.school||"");
  const status=extra.status!==undefined?extra.status:(prof.status||"");
  const data={
    uid:u.uid,
    name,
    username,
    usernameLower:username,
    nameLower:name.toLowerCase(),
    school,
    schoolLower:(school||"").toLowerCase(),
    status,
    total_minutes_focused:getTotalMinutesFocused(),
    streak:getStreak(),
    updatedAt:new Date().toISOString(),
  };
  try{await fsdb().collection('profiles').doc(u.uid).set(data,{merge:true});}catch(e){}
  // name/email intentionally omitted here — the users/{uid} security rules
  // only allow a specific onboarding-field allowlist for client writes (see
  // firestore.rules); name already lives on the public profiles doc above,
  // and email is populated server-side via the Admin SDK (api/me.js).
  try{await fsdb().collection('users').doc(u.uid).set({updatedAt:new Date().toISOString()},{merge:true});}catch(e){}
}
// Adds a school to the shared cross-user directory SchoolSelect searches --
// fire-and-forget, called once at an actual save point (never from the
// picker's own onChange, which fires every keystroke). The doc id is a
// slug of the name, so two students typing different casing/spacing for
// the same real school land on the exact same doc with no query-time dedup
// needed. firestore.rules only allows create, never update/delete, so a
// `set` against an already-existing doc is rejected by the rules engine
// (evaluated as an update) -- the catch below is that expected, harmless
// "someone already added this" outcome, not a real failure.
function ensureSchoolInDirectory(name,type){
  if(!name||!name.trim())return;
  const slug=name.trim().toLowerCase().replace(/[^a-z0-9]+/g,"-").replace(/^-+|-+$/g,"").slice(0,100);
  if(!slug)return;
  try{fsdb().collection('schools').doc(slug).set({name:name.trim(),nameLower:name.trim().toLowerCase(),type,createdAt:new Date().toISOString()}).catch(()=>{});}catch(e){}
}
const dayKey=(d)=>{const x=d||new Date();return x.getFullYear()+"-"+String(x.getMonth()+1).padStart(2,"0")+"-"+String(x.getDate()).padStart(2,"0");};
function daysOverdue(ev){if(!ev.deadline)return 0;if(ev.date<=ev.deadline)return 0;const d1=new Date(ev.date),d2=new Date(ev.deadline);return Math.ceil((d1-d2)/86400000);}
function daysUntilDeadline(ev){if(!ev.deadline)return null;const d1=new Date(ev.deadline),d2=new Date(dayKey());return Math.ceil((d1-d2)/86400000);}
// Per-task one-shot notification scheduling used to live here, but it only
// fired if the tab stayed open uninterrupted from the moment of creation —
// it never survived a refresh, and never re-armed after a drag/rebalance
// moved a task to a new time. Replaced by the polling-based upcomingTask
// reminder effect in App() (checks the live task list every 30s against the
// real clock), which covers every task regardless of when/how it was
// scheduled. See that effect for the single source of truth now.
function requestNotifPermission(){if(!("Notification" in window))return;Notification.requestPermission();}
function stripHtml(html){return(html||"").replace(/<[^>]*>/g," ");}
function sanitizeHtml(html){if(typeof DOMPurify==='undefined')return html||'';return DOMPurify.sanitize(html||'',{ALLOWED_TAGS:['p','br','h1','h2','h3','h4','h5','h6','ul','ol','li','strong','em','b','i','u','s','blockquote','span','a','code','pre','table','thead','tbody','tr','th','td','hr','sub','sup'],ALLOWED_ATTR:['href','target','rel'],FORCE_BODY:true,ALLOW_UNKNOWN_PROTOCOLS:false});}
function wordCountOf(html){var txt=stripHtml(html).trim();return txt?txt.split(/\s+/).length:0;}
function readabilityOf(html){
  var txt=stripHtml(html).trim();
  if(!txt)return{grade:"—",level:""};
  var words=txt.split(/\s+/).filter(Boolean);
  var sentences=txt.split(/[.!?]+/).filter(function(s){return s.trim().length>0;});
  var syllables=words.reduce(function(acc,w){
    var clean=w.toLowerCase().replace(/[^a-z]/g,"");
    var m=clean.match(/[aeiouy]+/g);
    return acc+Math.max(1,m?m.length:1);
  },0);
  var wc=words.length,sc=Math.max(1,sentences.length);
  var ease=206.835-1.015*(wc/sc)-84.6*(syllables/wc);
  var gradeNum=0.39*(wc/sc)+11.8*(syllables/wc)-15.59;
  var letter=ease>=90?"A+":ease>=80?"A":ease>=70?"B+":ease>=60?"B":ease>=50?"C+":ease>=30?"C":"D";
  var lvl=gradeNum<=6?"Grade 6 or below":gradeNum>=16?"College level":"Grade "+Math.max(1,Math.round(gradeNum));
  return{grade:letter,level:lvl};
}
function touchStreak(){const days=lsGet("days",[]);const t=dayKey();if(!days.includes(t)){days.push(t);lsSet("days",days);upsertProfile();}}
function getStreak(){const days=new Set(lsGet("days",[]));let n=0;const d=new Date();while(days.has(dayKey(d))){n++;d.setDate(d.getDate()-1);}return n;}
// Shared 91-day heatmap data — used by both Profile/nav's StreakDetailModal
// and (previously) Dashboard's inline streak card, so the two never disagree
// about what counts as an active day.
function computeStreakHeatmap(){
  const loginDaysSet=new Set(lsGet("days",[]));
  const minsByDay={};
  lsGet("sessions",[]).forEach(s=>{minsByDay[s.d]=(minsByDay[s.d]||0)+(s.m||0);});
  const cells=[];
  const now=new Date();
  for(let i=90;i>=0;i--){
    const d=new Date(now);d.setDate(now.getDate()-i);
    const k=dayKey(d);
    const mins=minsByDay[k]||0;
    let lvl=0;
    if(loginDaysSet.has(k)||mins>0)lvl=mins>=120?4:mins>=60?3:mins>=30?2:1;
    cells.push(lvl);
  }
  let longest=0,cur=0;
  cells.forEach(v=>{if(v>0){cur++;if(cur>longest)longest=cur;}else{cur=0;}});
  return {cells,longest};
}
function streakCellColor(lvl){
  if(!lvl)return T.mode==="light"?"rgba(8,12,40,0.06)":"rgba(255,255,255,0.06)";
  return [null,T.lime+"40",T.lime+"80",T.limeDk,T.forest][lvl];
}
function logSession(mins,mode){const s=lsGet("sessions",[]);s.push({d:dayKey(),m:mins,t:Date.now(),mode:mode||"Focus"});lsSet("sessions",s);upsertProfile();}
// Lightweight in-progress-session record, so a Lock-In session survives
// the tab losing focus, the machine sleeping, or the timer widget getting
// closed before it naturally finishes — none of which currently leave any
// trace, silently discarding real focus time (see checkpointTimerSession's
// callers in TaskTimerModal and the recovery check on app load). Written
// once at start and every ~20s while running, not on every tick.
const getTimerCheckpoint=()=>lsGet("activeTimerSession",null);
const checkpointTimerSession=(taskId,title,totalMins,focusElapsedSecs,phase)=>lsSet("activeTimerSession",{taskId,title,totalMins,focusElapsedSecs,phase,lastCheckpointAt:Date.now()});
const clearTimerCheckpoint=()=>lsSet("activeTimerSession",null);
// Pure decision logic for what to do with a checkpoint found on app load —
// kept separate from the UI/React wiring so it's directly testable. Never
// recovers a checkpoint whose task no longer exists or is no longer
// pending (already done some other way, deleted, etc.) — nothing to
// recover in that case, not an error.
function resolveOrphanedCheckpoint(checkpoint,events){
  if(!checkpoint||!checkpoint.taskId)return null;
  const task=events.find(e=>e.id===checkpoint.taskId);
  if(!task||task.status!=="pending")return null;
  // Never over-credit: the elapsed value is whatever was last checkpointed,
  // never estimated forward from the gap since then (the tab could've been
  // closed/asleep for any part of that gap) — same conservative instinct
  // as completeSession's own safeMins=Math.min(mins,totalMins) cap.
  const elapsedMins=Math.max(1,Math.min(checkpoint.totalMins||task.duration||1,Math.round((checkpoint.focusElapsedSecs||0)/60)));
  return{task,elapsedMins,checkpoint};
}
// "Similar tasks usually take you ~Xm" — median of real logged time (not
// the originally-guessed duration) for past completed tasks in the same
// subject+kind. Removes the time-blindness guesswork of estimating a new
// task's length from scratch every time; returns null until there's at
// least one real data point to go on.
// Phase 3 — flashcard/exam review sessions counting down to a date. Pure
// scheduling math, no AI/credit cost: spacing gets denser the closer the
// date gets (classic spaced-repetition shape). desiredCount is student-
// chosen (clamped to 1-6) rather than a hardcoded cap, so "how many
// sessions do you want" is a real choice, not something the algorithm
// decides alone — offsets still contract toward the date the same way
// the old fixed 4-session curve did. Offsets are "days before the target
// date"; anything that would land in the past (or on the date itself) is
// dropped, so asking for more sessions than there's room for just yields
// fewer, never schedules into the past.
function computeReviewOffsets(daysUntil,desiredCount){
  const count=Math.max(1,Math.min(6,desiredCount||4));
  if(daysUntil<0)return []; // exam already passed
  if(daysUntil<2){
    // Too imminent for the expanding curve to fit even its first (smallest)
    // interval -- still worth one cram session today, or on the exam date
    // itself, rather than the exam getting zero auto-scheduled prep at all
    // just because it's the most urgent case.
    return daysUntil===0?[0]:[1];
  }
  const offsets=[];
  let offset=1;
  for(let i=0;i<count;i++){
    if(offset>=daysUntil)break;
    offsets.push(offset);
    offset=offset*2+1; // 1, 3, 7, 15, 31, 63 days out
  }
  return offsets.reverse();
}
function computeReviewDates(examDateKey,todayKey,desiredCount){
  const exam=new Date(examDateKey+"T12:00:00");
  const today=new Date(todayKey+"T12:00:00");
  const daysUntil=Math.round((exam-today)/86400000);
  return computeReviewOffsets(daysUntil,desiredCount).map(o=>{
    const d=new Date(exam);d.setDate(d.getDate()-o);return dayKey(d);
  }).sort();
}
// A pop quiz doesn't deserve the same 4-session buildup as a final — lighter
// default, still fully student-adjustable via the count stepper either way.
const defaultSessionCountFor=(examWeight)=>examWeight==="quiz"?2:4;
function suggestDurationFor(subject,kind){
  const events=lsGet("events",[]).filter(e=>e.status==="done"&&e.timeSpent&&e.subject===subject&&e.kind===kind);
  if(events.length===0)return null;
  const sorted=events.map(e=>e.timeSpent).sort((a,b)=>a-b);
  const mid=Math.floor(sorted.length/2);
  const median=sorted.length%2?sorted[mid]:Math.round((sorted[mid-1]+sorted[mid])/2);
  return Math.max(5,Math.round(median/5)*5);
}
// Shared by deck review scheduling (Flashcards) and practice-exam
// scheduling (Studlin Prep) -- both are "N spaced sessions counting down
// to an exam date," and this is the one place that math lives so the two
// can never drift into different placement behavior for conceptually the
// same job. Pulled out of Flashcards' own buildReviewSessions (which now
// just forwards here) rather than writing a second copy for practice
// exams. Not a pure function -- reads live events/routines/prefs, same as
// every other scheduling helper in this file -- but deterministic given
// the same stored state, same as those.
// Shared by Flashcards' exam-link picker and Studlin Prep's exam hub list
// -- both need "every exam still ahead of today, soonest first."
function upcomingExams(){
  return lsGet("events",[]).filter(e=>e.kind==="exam"&&e.date>=dayKey()).sort((a,b)=>a.date.localeCompare(b.date));
}
// Storage-only half of linking a deck to an exam -- callers that keep
// their own local mirror of "decks" in React state (Flashcards) are
// responsible for updating that mirror with the returned array after
// calling this, the same convention every other scheduling helper in this
// file already follows (read/write localStorage directly, never assume a
// caller's component state).
// Additive, not overwriting -- a deck can now be linked to more than one
// exam. examEventId (singular) stays mirrored to whichever exam was
// linked FIRST so every existing `d.examEventId===...` read site across
// the file (there are about 15) keeps working completely unchanged;
// examEventIds (the real, complete list) is the new source of truth for
// anywhere that needs to know about every linked exam, not just the
// first. Deduped via Set so linking the same exam twice is a no-op.
function linkDeckToExamStorage(deckId,examEventId){
  const next=lsGet("decks",[]).map(d=>{
    if(d.id!==deckId)return d;
    const ids=Array.from(new Set([...(d.examEventIds||(d.examEventId?[d.examEventId]:[])),examEventId]));
    return {...d,examEventId:d.examEventId||examEventId,examEventIds:ids};
  });
  lsSet("decks",next);
  return next;
}
// deck.examEventId (singular, legacy-compatible) vs deck.examEventIds
// (the real, complete list going forward) -- this is the one place that
// reconciles the two shapes, so every read site elsewhere just calls
// this instead of re-deriving the same fallback logic differently in
// three places.
function deckExamIds(deck){
  if(deck.examEventIds&&deck.examEventIds.length>0)return deck.examEventIds;
  return deck.examEventId?[deck.examEventId]:[];
}
function deckLinkedToExam(deck,examId){
  return deckExamIds(deck).includes(examId);
}
function buildSpacedSessionPreviews(examDate,subject,count,duration){
  const dates=computeReviewDates(examDate,dayKey(),count);
  const d=duration||suggestDurationFor(subject,"study block")||25;
  const events=lsGet("events",[]);
  const routines=getWeeklyRoutine();
  const prefs=getSchedulePreferences();
  let working=events;
  return dates.map(date=>{
    const slot=findReliableSlotFor(working,routines,prefs,date,prefs.workStartTime,d,examDate,5);
    if(!slot)return null;
    working=working.concat([{date:slot.date,time:slot.time,duration:d}]);
    return {date:slot.date,time:slot.time,duration:d,include:true,placementReason:slot.reason||null};
  }).filter(Boolean);
}
function sessionStats(){
  const s=lsGet("sessions",[]);
  const weekAgo=Date.now()-6*86400000;
  const week=s.filter(x=>x.t>=weekAgo);
  const today=s.filter(x=>x.d===dayKey());
  const weekMin=week.reduce((a,x)=>a+x.m,0);
  const todayMin=today.reduce((a,x)=>a+x.m,0);
  return {weekCount:week.length,weekMin,todayMin,avg:week.length?Math.round(weekMin/week.length):0,todayCount:today.length};
}
const fmtH=(m)=>m>=60?Math.floor(m/60)+"h "+(m%60)+"m":m+"m";
function getPlan(){return lsGet("plan","Free");}
function setPlanLS(p){lsSet("plan",p);}
function getCreditLimit(){const p=getPlan();return p==="Max"?500:p==="Pro"?200:120;}
function getCredits(){return lsGet("credits",getCreditLimit());}
function setCreditsLS(n){lsSet("credits",Math.max(0,n));}
const CREDIT_COST={standard:1,flash:1};
// Named, per-feature monthly limits on Free — each capped feature gets its
// own honest counter ("3 syllabus scans left this month") instead of
// quietly eating into one abstract "AI credits" pool nobody understands.
// Pro and Max are uncapped on all three. Purely client-side (same trust
// model as credits everywhere else in this app — no server enforcement
// exists yet).
function makeMonthlyUsage(storageKey){
  return function(){
    const monthKey=new Date().toISOString().slice(0,7);
    const stored=lsGet(storageKey,{month:monthKey,count:0});
    return stored.month===monthKey?stored:{month:monthKey,count:0};
  };
}
function daysUntilReset(){const n=new Date();const e=new Date(n.getFullYear(),n.getMonth()+1,1);return Math.ceil((e-n)/86400000);}

const SYLLABUS_SCAN_LIMIT=11;
