// ─── XP · LEVEL · STREAK · PLAN (all derived from real activity) ───────────────
const DOW_FULL=["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"];
const MON_SHORT=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
function todayLabel(){const d=new Date();return DOW_FULL[d.getDay()]+" · "+MON_SHORT[d.getMonth()]+" "+d.getDate();}
function weekNo(){const d=new Date();const start=new Date(d.getFullYear(),0,1);return Math.ceil((((d-start)/86400000)+start.getDay()+1)/7);}

// Deterministic, non-AI fallback for syllabus deadline extraction — mirrors
// fallbackSchedule's role for AI Schedule Mode: if the AI call throws or
// returns nothing usable, this guarantees the feature still returns SOMETHING
// rather than dead-ending. Naive regex date-scan, so every match is tagged
// confidence:"low" — the review modal flags these for the student to check.
function regexScanDeadlines(text){
  const lines=(text||"").split("\n");
  const results=[];
  const monthPattern=new RegExp("("+MON_SHORT.join("|")+")[a-z]*\\.?\\s+(\\d{1,2})(?:st|nd|rd|th)?(?:,?\\s*(\\d{4}))?","gi");
  const numericPattern=/\b(\d{1,2})\/(\d{1,2})(?:\/(\d{2,4}))?\b/g;
  const now=new Date();
  const titleFrom=(line)=>{const t=line.replace(/^[\s\-*•\d.)]+/,"").trim().slice(0,60);return t||"Deadline";};
  const kindFrom=(line)=>/exam|midterm|final|quiz|test/i.test(line)?"exam":"deadline";
  const rollYear=(month,day,year)=>{
    if(year)return year.length===2?"20"+year:year;
    const candidate=new Date(now.getFullYear(),month,day);
    return String(candidate<now?now.getFullYear()+1:now.getFullYear());
  };
  lines.forEach(line=>{
    if(results.length>=40)return;
    let m;
    monthPattern.lastIndex=0;
    if((m=monthPattern.exec(line))){
      const monthIdx=MON_SHORT.findIndex(mo=>mo.toLowerCase()===m[1].toLowerCase());
      const day=parseInt(m[2],10);
      const year=rollYear(monthIdx,day,m[3]);
      results.push({title:titleFrom(line),date:year+"-"+String(monthIdx+1).padStart(2,"0")+"-"+String(day).padStart(2,"0"),kind:kindFrom(line),confidence:"low"});
      return;
    }
    numericPattern.lastIndex=0;
    if((m=numericPattern.exec(line))){
      const month=parseInt(m[1],10)-1,day=parseInt(m[2],10);
      if(month<0||month>11||day<1||day>31)return;
      const year=rollYear(month,day,m[3]);
      results.push({title:titleFrom(line),date:year+"-"+String(month+1).padStart(2,"0")+"-"+String(day).padStart(2,"0"),kind:kindFrom(line),confidence:"low"});
    }
  });
  return results;
}
// Deterministic "never dead-end" fallback for the Brain Dump parser (see
// parseBrainDump in CalendarTab) — splits on commas/newlines/" and " and
// treats every fragment as a plain to-do. Deliberately never guesses a
// study duration here: without the AI actually reading the text, inventing
// a number would be a worse failure mode than just asking the student to
// schedule it themselves via the checklist.
function fallbackSplitBrainDump(text){
  return (text||"")
    .split(/[,\n]|(?:\s+and\s+)/i)
    .map(s=>s.trim().replace(/^[\s\-*•.]+/,""))
    .filter(s=>s.length>2)
    .slice(0,15)
    .map(s=>({title:s.charAt(0).toUpperCase()+s.slice(1),kind:"todo",durationMin:null,dueDate:null,needsDuration:false}));
}
// Levels map strictly to real Lock-In Timer minutes — no streak/login/task
// bonuses, no penalty deductions, no starting offset. An honest sum of
// every session actually logged, nothing else.
function getTotalMinutesFocused(){
  const s=lsGet("sessions",[]);
  return s.reduce((acc,x)=>acc+(x.m||0),0);
}
function applyOverduePenalties(){
  const today=dayKey();
  const events=lsGet("events",[]);
  const penalized=lsGet("penalizedTasks",{});
  let added=0;
  events.forEach(ev=>{
    if(penalized[ev.id])return;
    if(ev.status!=="pending")return;
    if(ev.date>=today)return;
    if(ev.deadline&&ev.deadline<today)return;
    // Two live scales coexist in the same events array (legacy raw 0-10,
    // current Add/Edit Task slider 0-1000) -- reading .priority/.difficulty
    // raw here made this penalty's magnitude differ by ~18,000x between two
    // functionally-identical overdue tasks depending only on which UI
    // created them. normalizeTaskVal (0-1) *10 puts both back on the same
    // ~1-10 magnitude this formula's constants were originally tuned
    // around, instead of collapsing every legacy-scale task's penalty
    // toward near-zero.
    const p=normalizeTaskVal(ev.priority,1)*10;
    const d=normalizeTaskVal(ev.difficulty,1)*10;
    const pen=Math.round((ev.duration||25)*p*d);
    added+=pen;
    penalized[ev.id]=true;
  });
  if(added>0){lsSet("xpPenaltyTotal",(lsGet("xpPenaltyTotal",0)+added));lsSet("penalizedTasks",penalized);}
}
function levelInfo(){const minutes=getTotalMinutesFocused();const per=300;const level=Math.floor(minutes/per)+1;const into=minutes-(level-1)*per;const title=getProfTitle(minutes);const nextTier=PROF_TIERS.find(t=>t.minMinutes>minutes)||null;const curTierMinutes=(PROF_TIERS.slice().reverse().find(t=>minutes>=t.minMinutes)||PROF_TIERS[0]).minMinutes;const tierPct=nextTier?Math.round(Math.max(0,Math.min(100,(minutes-curTierMinutes)/(nextTier.minMinutes-curTierMinutes)*100))):100;return {minutes,level,into,per,toNext:per-into,pct:Math.round(into/per*100),title,nextTier,tierPct};}
function weekStreak(){const days=new Set(lsGet("days",[]));const now=new Date();const dow=(now.getDay()+6)%7;const mon=new Date(now);mon.setDate(now.getDate()-dow);return ["M","T","W","T","F","S","S"].map((lab,i)=>{const d=new Date(mon);d.setDate(mon.getDate()+i);const k=dayKey(d);const today=k===dayKey(now);return {lab,on:days.has(k),today,future:d>now&&!today};});}
// ─── ADVANCED SCHEDULING SYSTEM (5 features integrated) ──────────────────────
// Feature 1: User preference storage + getters/setters (complete with all onboarding preferences)
function getSchedulePreferences(){
  const def={
    workStartTime:"10:00",
    workEndTime:"18:00",
    bedtime:"23:00",
    // The real, UI-wired difficulty preference (Settings, the onboarding
    // wizard) — "easyFirst"/"balanced"/"hardFirst", read by scoreTask.
    // taskDifficultyPreference below is a separate, older key ("FIRST"/
    // "LAST"/"NONE") that nothing in the UI writes anymore; kept only so
    // legacy stored prefs objects don't lose the field, not read by any
    // live scoring path.
    difficultyPreference:"balanced",
    taskDifficultyPreference:"NONE",
    bufferMarginStrategy:"15_MIN",
    // Optional separate Sat/Sun hours — off by default, so every existing
    // account keeps its current single-window behavior until someone
    // explicitly turns this on in Settings.
    weekendEnabled:false,
    weekendStartTime:"10:00",
    weekendEndTime:"18:00",
    // Student-declared peak-focus buckets (TIER0_HOUR_BUCKETS ids). Opt-in,
    // empty by default — Tier 0 only special-cases a bucket here if the
    // student explicitly added it; this is never inferred on its own.
    peakHourBuckets:[],
  };
  const stored=lsGet("schedulePrefs",def);
  return {...def,...stored};
}
// Proportional Breathing Room — replaces the old fixed 3-tier break buckets
// with one continuous formula, anchored close to the previous tiers
// (25min->5, 60min->10, 90min->15) but still scaling past 120min instead of
// plateauing there. Used both as the Lock-In Timer's default break length
// and as a trailing buffer after existing blocks during gap-finding.
function computeBreathingRoom(mins){
  return Math.max(5,Math.min(20,Math.round((mins*0.15)/5)*5));
}
function setSchedulePreferences(prefs){
  lsSet("schedulePrefs",prefs);
}

// Helper: convert "HH:MM" to minutes since midnight
function timeToMinutes(timeStr){
  if(!timeStr)return 0;
  const [h,m]=timeStr.split(":").map(Number);
  return h*60+m;
}

// Helper: convert minutes since midnight back to "HH:MM"
// Clamped, never wrapped: a caller that overflows past end-of-day (a late
// catch-up window colliding with a near-midnight workEndTime, or "now"
// itself sitting within ~15min of midnight) gets an honestly-late 23:59,
// never a silent wrap into tomorrow's early morning that would look like
// an unrelated slot on the same date, and never an invalid "24:xx"/"25:xx"
// string (see fmtClock12's own guard, and the reminder-notification effect's
// `new Date(ev.date+"T"+ev.time)`, both of which mis-handle that).
function minutesToTime(mins){
  const clamped=Math.max(0,Math.min(1439,Math.round(mins)));
  const h=Math.floor(clamped/60);
  const m=clamped%60;
  return String(h).padStart(2,"0")+":"+String(m).padStart(2,"0");
}

// Normalize a stored priority/difficulty value to 0-1.
// New tasks (Phase 3+) store 0-1000; legacy tasks store 0-10.
function normalizeTaskVal(v,defaultVal){
  const n=v!=null?v:defaultVal;
  return n>10?n/1000:n/10;
}

// Weighted scoring formula (returns 0-1000 integer, higher = schedule sooner).
// W_priority=0.35, W_deadline=0.35, W_difficulty=0.20, W_streak=0.10
function scoreTask(task,prefs,streak){
  const p=normalizeTaskVal(task.priority,5);

  const rawDiff=task.difficulty!=null?task.difficulty:500;
  const d=normalizeTaskVal(rawDiff,5);

  let urgency=0.3;
  if(task.deadline){
    const h=(new Date(task.deadline+"T23:59:00").getTime()-Date.now())/3600000;
    if(h<=0)urgency=1.0;
    else if(h<=24)urgency=1.0;
    else if(h<=48)urgency=0.8;
    else if(h<=72)urgency=0.6;
    else urgency=Math.max(0.3,0.6-(h-72)/240);
  }

  // regression: this used to read prefs.taskDifficultyPreference ("FIRST"/
  // "LAST"/"NONE"), a key nothing in the UI ever writes -- Settings and the
  // onboarding wizard both save the student's Easy/Hard First choice as
  // prefs.difficultyPreference ("easyFirst"/"hardFirst"/"balanced"). The two
  // keys were never reconciled, so this weight silently sat at the neutral
  // 0.5 default for every account regardless of what was actually picked.
  const pref=(prefs&&prefs.difficultyPreference)||"balanced";
  const diffWeight=pref==="hardFirst"?d:pref==="easyFirst"?1-d:0.5;

  const streakBoost=(streak||0)>=3?1.0:0.0;

  const raw=0.35*p+0.35*urgency+0.20*diffWeight+0.10*streakBoost;
  return Math.round(Math.min(1,raw)*1000);
}

// Re-score and re-slot all pending flexible tasks on dateKey.
// Returns the full updated events array; does not persist.
function rebalanceDay(dateKey,allEvents,routines,prefs){
  const streak=getStreak();
  const isFixed=isLeadInFixed;
  // userPinned tasks (manually dragged, or hand-typed a time in Add Task /
  // Edit) are excluded from reshuffling the same way FIXED kinds are — they
  // still occupy their slot (fall into `rest`, still block other tasks from
  // landing on top of them) but the algorithm never picks them back up and
  // moves them again just because a new task got added to the day.
  // A duration-less deadline marker (a syllabus-scanned "this is due" fact,
  // not a real work block) isn't a FIXED kind — only kind:"exam" is — so
  // without this it would get pulled into the reshuffle, scored as
  // maximally urgent (its own deadline is its own date), and given a fake
  // 60-min footprint at the front of the day, potentially displacing real
  // study blocks. Same "no duration = fact, not a task" rule as isDuePill
  // in WeeklyPlanner and isTier0Missed's implicit same-day-deadline guard.
  // Fixed/checklist/done/pinned exclusions now live in the shared
  // isReorderableTask (also used by Today's Plan) -- this layers on the
  // two constraints specific to an actual reshuffle: must be today, and
  // must already be a real, duration-bearing work block.
  const isFlexPending=function(e){return e.date===dateKey&&e.time&&e.duration&&isReorderableTask(e);};

  const flex=allEvents.filter(isFlexPending);
  if(flex.length===0)return allEvents;

  const rest=allEvents.filter(function(e){return !isFlexPending(e);});

  const occupiedBase=rest.filter(function(e){return e.date===dateKey&&e.time;}).map(function(e){
    return{start:timeToMinutes(e.time)-(isFixed(e)?LEAD_IN_BUFFER_MINS:0),end:timeToMinutes(e.time)+(e.duration||30)+computeBreathingRoom(e.duration||30)};
  });
  expandRoutineOccurrences(routines||[],dateKey,dateKey)
    .filter(function(r){return r.kind!=="free period";})
    .forEach(function(r){occupiedBase.push({start:timeToMinutes(r.time)-(isFixed(r)?LEAD_IN_BUFFER_MINS:0),end:timeToMinutes(r.time)+(r.duration||30)+computeBreathingRoom(r.duration||30)});});

  // With only one flexible task, there's nothing to reorder relative to —
  // leave it exactly where it is unless it's actually colliding with
  // something fixed/pinned it needs to route around (a pinned task now
  // occupying that exact slot, for instance).
  if(flex.length<2){
    const solo=flex[0];
    const soloStart=timeToMinutes(solo.time);
    const soloEnd=soloStart+(solo.duration||60);
    const collides=occupiedBase.some(function(o){return!(soloEnd<=o.start||soloStart>=o.end);});
    if(!collides)return allEvents;
  }

  const sorted=[...flex].sort(function(a,b){return scoreTask(b,prefs,streak)-scoreTask(a,prefs,streak);});

  const dayWindow=getWorkWindowMinsFor(prefs,dateKey);
  let prefStart=dayWindow.start;
  const prefEnd=dayWindow.end;
  const isToday=dateKey===dayKey();
  // Same "never re-slot into the past" floor as findOpenSlotFor — without
  // this, saving or editing any second task today silently snapped every
  // flexible task on the day back to workStartTime, clobbering times that
  // aiArrange/findOpenSlotFor had already correctly placed after "now".
  if(isToday){
    const now=new Date();
    const nowFloorMins=Math.ceil((now.getHours()*60+now.getMinutes()+15)/15)*15;
    prefStart=Math.max(prefStart,nowFloorMins);
  }
  // Same end-of-day catch-up buffer as findOpenSlotFor — a rebalance
  // triggered late in the day (e.g. adding a second task at 9pm) shouldn't
  // strand overflow tasks just because normal work hours are full. Capped
  // at 1440 (see findOpenSlotFor's matching cap) so a late workEndTime
  // preference can't push this past midnight into an invalid time.
  const dayEnd=isToday?Math.min(1440,prefEnd+CATCHUP_BUFFER_MINS):prefEnd;

  const occupied=occupiedBase.slice();

  const reassigned=sorted.map(function(task){
    const dur=task.duration||60;
    if(prefStart+dur>dayEnd)return task; // no room left even with the catch-up buffer — leave it where it was rather than force a slot
    for(let t=prefStart;t+dur<=dayEnd;t+=15){
      if(!occupied.some(function(o){return!(t+dur<=o.start||t>=o.end);})){
        occupied.push({start:t,end:t+dur+computeBreathingRoom(dur)});
        return Object.assign({},task,{time:minutesToTime(t)});
      }
    }
    return task;
  });

  return rest.concat(reassigned);
}

// "Balance my week" — manually triggered only, never automatic. Everything
// else that moves more than one task at once in this file (Tier 0, Studlin
// Reschedule) either acts on a single already-missed/already-targeted task
// or is explicitly requested for one specific day; silently redistributing
// several already-committed tasks across a whole week in the background
// would be the highest blast-radius thing this app does. Pure data in/out,
// same review-then-commit discipline as commitSyllabusEvents/confirmReview
// — nothing is written until the student picks specific moves and applies
// them from the review screen.
const WEEK_BALANCE_DAYS=7;
// A day only counts as "heavy" if it's meaningfully above the week's own
// average flexible-task load — avoids proposing a token 15-minute shuffle
// between two days that are already close to even.
const WEEK_BALANCE_HEAVY_THRESHOLD_MINS=45;
// "Heavy relative to average" is meaningless when the week barely has
// anything scheduled at all — one 60-minute task on an otherwise empty
// week trivially clears WEEK_BALANCE_HEAVY_THRESHOLD_MINS against a
// near-zero average, producing a technically-true but nonsensical "your
// week is lopsided" nudge for a single task. Require a real minimum
// amount of total flexible work in the window before "lopsided" is even
// a meaningful question to ask.
const WEEK_BALANCE_MIN_TOTAL_MINS=180;
function computeWeekBalancePlan(events,routines,prefs,startDateKey){
  const days=[];
  for(let i=0;i<WEEK_BALANCE_DAYS;i++){
    const d=new Date(startDateKey+"T12:00:00");d.setDate(d.getDate()+i);
    days.push(dayKey(d));
  }
  const isFixed=e=>TIER0_FIXED_KINDS.has(e.kind)||isCoopStudySession(e);
  // Same flexible-task definition rebalanceDay uses (isFlexPending above),
  // plus userPinned excluded the same way — a student who explicitly
  // pinned a task gets to keep it exactly where they put it, even here.
  const isFlex=e=>!isFixed(e)&&!e.checklist&&e.status==="pending"&&e.time&&e.duration&&!e.userPinned;
  const minutesFor=(dk,pool)=>pool.filter(e=>e.date===dk&&isFlex(e)).reduce((sum,e)=>sum+(e.duration||0),0);

  const before={};
  days.forEach(dk=>{before[dk]=minutesFor(dk,events);});
  const avg=days.reduce((sum,dk)=>sum+before[dk],0)/days.length;
  const totalMins=days.reduce((sum,dk)=>sum+before[dk],0);

  // Heaviest day first, so the worst day gets first crack at shedding load.
  // No day is ever "heavy" at all when the week's total flexible load is
  // too small for "average" to mean anything (see WEEK_BALANCE_MIN_TOTAL_MINS).
  const heavyDays=totalMins<WEEK_BALANCE_MIN_TOTAL_MINS?[]:days.filter(dk=>before[dk]-avg>=WEEK_BALANCE_HEAVY_THRESHOLD_MINS).sort((a,b)=>before[b]-before[a]);

  let working=events.slice();
  const moves=[];
  heavyDays.forEach(heavyDk=>{
    // Recompute fresh — an earlier heavy day's move may have already
    // loaded this one up as a target, or already brought it back to average.
    while(minutesFor(heavyDk,working)-avg>=WEEK_BALANCE_HEAVY_THRESHOLD_MINS){
      // Same "safely movable" criteria findSlotWithEviction already trusts
      // for same-day eviction: real study blocks only, no imminent deadline
      // (more than a week out, or none at all) — never an exam, a fixed
      // commitment, or a task genuinely due soon.
      const candidates=working.filter(e=>e.date===heavyDk&&isFlex(e)&&e.kind==="study block"&&(!e.deadline||daysUntilDeadline(e)>7))
        .sort((a,b)=>(b.duration||0)-(a.duration||0));
      if(candidates.length===0)break; // this day is heavy but nothing on it is safely movable
      const task=candidates[0];
      // Target the currently-lightest OTHER day in the window, recomputed
      // fresh for each task so a big task doesn't all land on the same
      // just-lightened day.
      const targets=days.filter(dk=>dk!==heavyDk).map(dk=>({dk,mins:minutesFor(dk,working)})).sort((a,b)=>a.mins-b.mins);
      let moved=false;
      for(const t of targets){
        // findLegalSlotOrNull only — the hard-wall-safe version. A move
        // that can't land on a genuinely free, non-overlapping, still-
        // before-its-own-deadline slot is not included in the plan at all,
        // never forced through findOpenSlotFor's unsafe fallback.
        const slot=findLegalSlotOrNull(working.filter(e=>e.id!==task.id),routines,prefs,t.dk,prefs.workStartTime,task.duration,task.deadline||null);
        if(!slot)continue;
        working=working.map(e=>e.id===task.id?{...e,date:slot.date,time:slot.time}:e);
        moves.push({id:task.id,title:task.title,duration:task.duration,fromDate:task.date,fromTime:task.time,toDate:slot.date,toTime:slot.time});
        moved=true;
        break;
      }
      // No legal day anywhere in the window for this specific task — drop
      // just this one candidate and stop trying this heavy day rather than
      // looping on the same unmovable task forever.
      if(!moved)break;
    }
  });

  const perDay=days.map(dk=>({date:dk,minutesBefore:before[dk],minutesAfter:minutesFor(dk,working)}));
  return {moves,perDay};
}
// Proactive nudge toward the (already-real, preview-then-confirm) "Balance
// my week" flow above — that flow was manual-trigger-only, so a student
// had to remember it exists. Single cooldown timestamp (not per-bucket
// like detectStrugglingBucket/detectPeakHourInsight) since there's only
// one week to balance, not several independent buckets. Shorter cooldown
// than those two (3 days, not 14) since "is this week heavy" is a
// week-scoped question that goes stale fast — a dismissal shouldn't
// silence it deep into a different, genuinely-overloaded week.
const WEEK_BALANCE_NUDGE_COOLDOWN_MS=3*86400000;
function shouldShowWeekBalanceNudge(){
  const dismissedAt=lsGet("weekBalanceNudgeDismissedAt",0);
  return Date.now()-dismissedAt>=WEEK_BALANCE_NUDGE_COOLDOWN_MS;
}
function dismissWeekBalanceNudge(){
  lsSet("weekBalanceNudgeDismissedAt",Date.now());
}

// Studlin Reschedule's actual planning engine ("push everything back N
// days" / "clear this day" / "clear this week" / "skip class today").
// Lives at module scope (not inside CalendarTab, where it originally sat)
// because it never actually closed over any component-local state — every
// dependency (dayKey, getWeeklyRoutine, getSchedulePreferences, lsGet,
// findLegalSlotOrNull) is already module-level, so moving it here is a
// pure relocation with no behavior change. Two things that make this worth
// doing: it's testable in isolation now, and it's the exact function where
// a real bug was found and fixed (a duration-less due-date marker could
// have its actual due date moved by these commands — see isQualifying's
// carve-out below).
const PAUSE_QUALIFYING_KINDS=new Set(["study block","deadline","reminder"]);
// A syllabus-scanned due-date marker is kind:"deadline" but duration:null (a
// real assignment's own scheduled work block always has a real duration) —
// without this carve-out, "push everything back"/"clear this week"/a class
// skip would move the actual due date itself, which is a fact set by the
// professor, not student time Studlin is free to reschedule. Reminders keep
// duration:0 by design (a point-in-time nudge, not a block) and are
// legitimately reschedulable, so this only excludes "deadline" specifically,
// not the whole qualifying set. !ev.checklist mirrors isTier0Missed's own
// exclusion — a checklist item is a plain to-do with no inherent time and
// must never be assigned one, here just as much as during Tier 0's rollover.
// Module scope (not a closure inside computePausePlan) since
// computeClassSkipPlan needs it too.
const isQualifying=(ev)=>ev.status==="pending"&&PAUSE_QUALIFYING_KINDS.has(ev.kind)&&!(ev.kind==="deadline"&&ev.duration==null)&&!ev.checklist;
// Shared by the "skip_class" Tier-3 intent (skips every class-kind routine
// matching a weekday) and a single-occurrence skip triggered directly from
// the calendar UI (skips exactly one routineId) — both just need to hand in
// the routine id(s) already decided to be skipped and the date, and get back
// a computePausePlan-shaped preview so the same modal renders either one
// with no changes.
function computeClassSkipPlan(skippedIds,date){
  const routinesAll=getWeeklyRoutine();
  const label=skippedIds.length===0?"No class scheduled "+date:"Skip class, "+date;
  if(skippedIds.length===0)return{label,moved:[],couldntMove:[],skipRoutine:null};
  // Preview the freed slot without touching localStorage yet — pass a
  // routines list with the skipped rule(s) filtered out, same idea as
  // Tier 3's other intents computing entirely in-memory until Confirm. The
  // actual persisted skip (which every other scheduler in the app also
  // needs to see, not just this preview) only gets written in
  // confirmPausePlan.
  const routinesMinusSkipped=routinesAll.filter(r=>!skippedIds.includes(r.id));
  const prefsNow=getSchedulePreferences();
  const all=lsGet("events",[]);
  const candidates=all.filter(ev=>isQualifying(ev)&&ev.date>date)
    .sort((a,b)=>a.date===b.date?((a.time||"")<(b.time||"")?-1:1):(a.date<b.date?-1:1));
  let working=all;
  const moved=[];
  for(const ev of candidates){
    if(moved.length>=4)break;
    const slot=findLegalSlotOrNull(working.filter(e=>e.id!==ev.id),routinesMinusSkipped,prefsNow,date,prefsNow.workStartTime,ev.duration||30,ev.deadline||null);
    if(slot&&slot.date===date){
      moved.push({id:ev.id,title:ev.title,oldDate:ev.date,oldTime:ev.time,newDate:slot.date,newTime:slot.time});
      working=working.map(e=>e.id===ev.id?{...e,date:slot.date,time:slot.time}:e);
    }
  }
  return{label,moved,couldntMove:[],skipRoutine:{date,routineIds:skippedIds}};
}
// Suggests up to 3 pending qualifying tasks that would fit into a
// specific just-freed window (e.g. after deleting an event from the
// Weekly grid's Backspace shortcut) — deliberately simpler than the
// forward-scanning slot finders above: the window is already known and
// already empty (nothing else could have moved into it yet), so this
// only needs a straight duration-fits check and a soonest-deadline-first
// sort, not a search. Pure/no side effects — the caller decides
// whether/how to actually place one.
function computeFillSuggestions(freedDate,freedTime,freedDuration){
  const all=lsGet("events",[]);
  return all.filter(ev=>isQualifying(ev)&&ev.date>=freedDate&&(ev.duration||30)<=freedDuration)
    .sort((a,b)=>{
      const da=a.deadline||"9999-99-99",db=b.deadline||"9999-99-99";
      return da<db?-1:da>db?1:0;
    })
    .slice(0,3)
    .map(ev=>({id:ev.id,title:ev.title,duration:ev.duration||30}));
}
function computePausePlan(intent,forcedId){
  const today=dayKey();
  if(intent.intent==="move_event"||intent.intent==="retime_event"){
    const targetDate=intent.targetDate||today;
    let matched;
    if(forcedId){
      // Re-entry after the student picked one of several disambiguation
      // candidates — skip fuzzy matching entirely and look the exact id up
      // in the same pool matchEventByTitle would have searched.
      const pool=lsGet("events",[]).filter(ev=>ev.date===targetDate).concat(getRoutineOccurrencesForDate(targetDate));
      matched=pool.find(ev=>ev.id===forcedId)||null;
      if(!matched)return{label:"That event isn't on the calendar anymore",moved:[],couldntMove:[],noMatch:true};
    }else{
      const{matches}=matchEventByTitle(intent.target||"",targetDate);
      if(matches.length===0)return{label:"Couldn't find \""+(intent.target||"")+"\" on "+targetDate,moved:[],couldntMove:[],noMatch:true};
      if(matches.length>1)return{label:"Which one did you mean?",moved:[],couldntMove:[],disambiguate:matches.map(ev=>({id:ev.id,title:ev.title,date:ev.date,time:ev.time,isRoutine:!!ev.isRoutine,routineId:ev.routineId||null}))};
      matched=matches[0];
    }
    const all=lsGet("events",[]);
    const routinesNow=getWeeklyRoutine();
    const prefsNow=getSchedulePreferences();
    if(intent.intent==="move_event"){
      // No destination day named ("make it sometime") defaults to tomorrow,
      // not today — the student just said they can't make the original
      // slot, so offering that exact slot straight back would be wrong.
      const dest=intent.destDate||dayKey(new Date(new Date(matched.date+"T12:00:00").getTime()+86400000));
      const workingEvents=all.filter(e=>e.id!==matched.id);
      // If matched is a routine occurrence, its own rule is still active
      // (skip_class hasn't been applied — that only happens on Confirm) and
      // would otherwise self-collide with the search on any day it also
      // recurs on (e.g. moving a daily habit-adjacent class, or a
      // Mon/Wed/Fri class to another day it meets), falling all the way
      // through to the last-resort scan and landing at midnight. Excluding
      // the rule here mirrors skip_class's own routinesMinusSkipped pattern.
      const routinesForSearch=matched.isRoutine?routinesNow.filter(r=>r.id!==matched.routineId):routinesNow;
      const slot=findFixedEventSlot(workingEvents,routinesForSearch,prefsNow,dest,matched.time||"09:00",matched.duration||30);
      const moved=[{id:matched.id,title:matched.title,oldDate:matched.date,oldTime:matched.time,newDate:slot.date,newTime:slot.time,newDuration:matched.duration||30,isRoutine:!!matched.isRoutine,routineId:matched.routineId||null,kind:matched.kind,subject:matched.subject||""}];
      return{label:"Move "+matched.title,moved,couldntMove:[]};
    }
    // retime_event: figure out who else on targetDate now collides with the
    // event's new time window and reslot just those, leaving everything
    // else untouched.
    const newStart=intent.newStart;
    const newDuration=intent.newDuration||matched.duration||30;
    const newStartMins=timeToMinutes(newStart);
    const newEndMins=newStartMins+newDuration;
    const sameDayOthers=all.filter(e=>e.date===targetDate&&e.id!==matched.id)
      .concat(getRoutineOccurrencesForDate(targetDate).filter(o=>o.id!==matched.id));
    const displaced=sameDayOthers.filter(ev=>{
      if(!isQualifying(ev)||!ev.time)return false;
      const s=timeToMinutes(ev.time),e=s+(ev.duration||30);
      return !(newEndMins<=s||newStartMins>=e);
    }).sort((a,b)=>(a.time||"")<(b.time||"")?-1:1);
    // Drop the retimed item's own old-time entry (a no-op if it's a routine
    // occurrence, which was never in `events`) and every displaced item,
    // then stand in a synthetic block at the NEW time so nothing gets
    // reslotted on top of it. Note: if the retimed item is a routine
    // occurrence, its OLD-time slot still shows as occupied to the slot
    // finder (the routine rule itself isn't touched until Confirm), which
    // only makes reslotting slightly more conservative — it just won't
    // offer displaced tasks the now-freed old slot, never a double-booking.
    let working=all.filter(e=>e.id!==matched.id&&!displaced.some(d=>d.id===e.id))
      .concat([{id:"__retimed__"+matched.id,date:targetDate,time:newStart,duration:newDuration,kind:matched.kind||"busy block",status:"pending"}]);
    const moved=[{id:matched.id,title:matched.title,oldDate:matched.date,oldTime:matched.time,newDate:targetDate,newTime:newStart,newDuration,isRoutine:!!matched.isRoutine,routineId:matched.routineId||null,kind:matched.kind,subject:matched.subject||""}];
    const couldntMove=[];
    displaced.forEach(ev=>{
      const slot=findLegalSlotOrNull(working,routinesNow,prefsNow,ev.date,ev.time,ev.duration||30,ev.deadline||null);
      if(!slot){couldntMove.push({id:ev.id,title:ev.title,deadline:ev.deadline||null});return;}
      moved.push({id:ev.id,title:ev.title,oldDate:ev.date,oldTime:ev.time,newDate:slot.date,newTime:slot.time});
      working=working.concat([{...ev,date:slot.date,time:slot.time}]);
    });
    return{label:"Retime "+matched.title,moved,couldntMove};
  }
  if(intent.intent==="skip_class"){
    const date=intent.date||today;
    const dow=(new Date(date+"T12:00:00").getDay()+6)%7;
    const skippedIds=getWeeklyRoutine().filter(r=>r.kind==="class"&&r.days&&r.days.includes(dow)).map(r=>r.id);
    return computeClassSkipPlan(skippedIds,date);
  }
  let label,inWindow,computeNewDate;
  if(intent.intent==="shift"){
    const days=Math.max(1,Math.min(14,intent.days||1));
    label="Push everything back "+days+" day"+(days!==1?"s":"");
    inWindow=(ev)=>isQualifying(ev)&&ev.date>=today;
    computeNewDate=(ev)=>{const d=new Date(ev.date+"T12:00:00");d.setDate(d.getDate()+days);return dayKey(d);};
  }else if(intent.intent==="clear_day"){
    const date=intent.date||today;
    label="Clear "+date;
    inWindow=(ev)=>isQualifying(ev)&&ev.date===date;
    computeNewDate=()=>{const d=new Date(date+"T12:00:00");d.setDate(d.getDate()+1);return dayKey(d);};
  }else{
    const end=(()=>{const d=new Date();d.setDate(d.getDate()+6);return dayKey(d);})();
    label="Clear this week";
    inWindow=(ev)=>isQualifying(ev)&&ev.date>=today&&ev.date<=end;
    computeNewDate=()=>{const d=new Date();d.setDate(d.getDate()+7);return dayKey(d);};
  }
  const all=lsGet("events",[]);
  const routinesNow=getWeeklyRoutine();
  const prefsNow=getSchedulePreferences();
  const affected=all.filter(inWindow).sort((a,b)=>a.date===b.date?((a.time||"")<(b.time||"")?-1:1):(a.date<b.date?-1:1));
  let working=all.filter(ev=>!inWindow(ev));
  const moved=[],couldntMove=[];
  affected.forEach(ev=>{
    const desiredDate=computeNewDate(ev);
    const slot=findLegalSlotOrNull(working,routinesNow,prefsNow,desiredDate,ev.time||prefsNow.workStartTime,ev.duration||30,ev.deadline||null);
    if(slot){
      moved.push({id:ev.id,title:ev.title,oldDate:ev.date,oldTime:ev.time,newDate:slot.date,newTime:slot.time});
      working=working.concat([{...ev,date:slot.date,time:slot.time}]);
    }else{
      couldntMove.push({id:ev.id,title:ev.title,deadline:ev.deadline});
      working=working.concat([ev]);
    }
  });
  return {label,moved,couldntMove};
}

// Standalone wrapper around rebalanceDay for callers outside CalendarTab's
// React state (e.g. ChatDrawer, a sibling component with no access to
// CalendarTab's own commitTasks closure) — reads/writes localStorage
// directly, same idiom as scheduleAssignmentExtension and
// scheduleAttackBlockFollowUp.
function addTaskWithRebalance(task){
  const events=lsGet("events",[]);
  const next=rebalanceDay(task.date,events.concat([task]),getWeeklyRoutine(),getSchedulePreferences());
  lsSet("events",next);
  return next;
}

// Feature 3: Task priority scoring (0-1000 scale with exponential deadline urgency)
function calculateTaskPriority(task,allTasks){
  let score=0;
  const prefs=getSchedulePreferences();
  const now=new Date();
  
  // Base priority (user-set) -- normalizeTaskVal handles the two live
  // scales (legacy raw 0-10 vs. the current 0-1000 slider) the same way
  // scoreTask already does; a raw read here meant every slider-created
  // task (priority commonly ~500) silently tied at the max score below,
  // and the difficulty branch's raw >=3/<=2 checks similarly misfired for
  // almost any slider value.
  const basePriority=normalizeTaskVal(task.priority,3)*10;
  score+=basePriority*100;
  
  // Deadline urgency (exponential scaling as due date approaches)
  if(task.deadline){
    const dueDate=new Date(task.deadline);
    const hoursDue=(dueDate-now)/(1000*60*60);
    if(hoursDue<=0){
      score+=300;
    }else if(hoursDue<=6){
      score+=250;
    }else if(hoursDue<=24){
      score+=200;
    }else if(hoursDue<=72){
      score+=120;
    }else{
      score+=Math.max(0,100-hoursDue/24);
    }
  }
  
  // Difficulty preference weighting
  const diff=normalizeTaskVal(task.difficulty,2)*10;
  if(prefs.difficultyPreference==="hardFirst"&&diff>=3){
    score+=150;
  }else if(prefs.difficultyPreference==="easyFirst"&&diff<=2){
    score+=100;
  }
  
  // Duration penalty (longer tasks score lower to prioritize quick wins)
  const dur=task.duration||30;
  if(dur>90)score-=50;
  else if(dur>60)score-=25;
  
  return Math.min(1000,Math.max(0,score));
}

// Feature 4: Duration-aware chunking & auto-inject breaks -- splits a task
// longer than 90min into 45-min chunks + 15-min breaks, purely for Today's
// Plan's display. Only ever called on tasks that already have a real,
// committed `.time` (either a real calendar event's own time, or a slot
// Today's Plan itself just found for a genuinely timeless item) -- there's
// no anchor to chunk from otherwise, and this never changes what's
// actually on the calendar, only how one long sitting is broken up on
// screen.
function chunkTasksWithBreaks(tasks){
  const chunked=[];
  tasks.forEach(task=>{
    if((task.duration||0)<=90||!task.time){
      chunked.push(task);
      return;
    }
    const dur=task.duration;
    let chunks=Math.ceil(dur/45);
    // Avoid a near-empty trailing chunk (e.g. 91min -> 45/45/1, a study
    // block shorter than the 15-min break placed right before it) -- fold
    // the remainder into the last chunk instead of spawning a tiny extra
    // one when it'd be under a 20-min floor.
    if(chunks>1&&dur-((chunks-1)*45)<20)chunks-=1;
    let cursorMins=timeToMinutes(task.time);
    for(let i=0;i<chunks;i++){
      const chunkDur=i<chunks-1?45:dur-(45*(chunks-1));
      chunked.push({
        ...task,
        // Only the first chunk keeps the real event id -- Today's Plan's
        // checkbox and Reschedule button both key off a real events[] id
        // matching, and later chunks/breaks are display-only continuations
        // of the same real session, never independently actionable (see
        // Dashboard's row render, which gates on chunkIndex).
        id:i===0?task.id:task.id+"-chunk-"+i,
        title:task.title+(chunks>1?` (Part ${i+1}/${chunks})`:""),
        time:minutesToTime(cursorMins),
        duration:chunkDur,
        // The real session's own full duration, separate from this one
        // chunk's 45-min slice -- Reschedule (only ever offered on chunk 0)
        // needs to search for room for the WHOLE session, not just its
        // first piece, or it could suggest a day that only actually has
        // room for 45 minutes of it.
        fullDuration:dur,
        parentId:task.id,
        isChunk:true,
        chunkIndex:i,
      });
      cursorMins+=chunkDur;
      if(i<chunks-1){
        chunked.push({
          id:"break-"+task.id+"-"+i,
          title:"Break",
          time:minutesToTime(cursorMins),
          duration:15,
          isBreak:true,
          subject:"Rest",
          priority:1,
          status:task.status,
        });
        cursorMins+=15;
      }
    }
  });
  return chunked;
}

// Feature 5: Conflict detection (detect overlaps with hard events)
// Checks a proposed [startMins, startMins+duration) window against a list of
// already-occupied {start,end} slots. (This used to check `.time`/`.id`/
// `.isFlexible` on entries that never had those fields — always `false`,
// i.e. conflict detection was silently inert. Now it actually does interval
// overlap math against the shape callers actually pass.)
function detectConflicts(task,occupiedSlots,startMins){
  const taskDur=task.duration||30;
  const taskEnd=startMins+taskDur;
  return occupiedSlots.some(slot=>!(taskEnd<=slot.start||startMins>=slot.end));
}

// Feature 2+Features 1,3,4,5: Integrated advanced scheduler
function advancedSchedulePlanner(baseEvents){
  const prefs=getSchedulePreferences();
  const tk=dayKey();

  // Get all events for today — checklist to-dos are excluded, they have no
  // duration and never belong in the scheduled day plan.
  const events=baseEvents.filter(e=>e.date===tk&&!e.checklist);
  const now=new Date();
  const nowMins=timeToMinutes(String(now.getHours()).padStart(2,"0")+":"+String(now.getMinutes()).padStart(2,"0"));
  // Floor for placing anything today: now + 15min buffer, rounded up to the
  // 15-min grid this planner already steps on. Without this, flexible tasks
  // with no time yet always landed at workStartTime regardless of the clock.
  const nowFloorMins=Math.ceil((nowMins+15)/15)*15;

  // Time window constraints
  const todayWindow=getWorkWindowMinsFor(prefs,tk);
  const workStart=Math.max(todayWindow.start,nowFloorMins);
  const workEnd=todayWindow.end;

  // Separate hard (fixed/pinned/done, never reordered) from flexible --
  // isReorderableTask is the exact same predicate rebalanceDay uses for the
  // real calendar, so Today's Plan can never disagree with an actual
  // reshuffle about what counts as flexible.
  const hardEvents=events.filter(e=>e.time&&!isReorderableTask(e));
  // A flexible task that already has a real committed time (an Attack
  // Block session, exam-prep session, manual/AI-arranged block) keeps that
  // exact time -- this never runs it back through the slot scanner, so
  // Today's Plan can never show a different time than the real Calendar
  // for the same event. Only a genuinely timeless due-today item (nothing
  // scheduled for it yet) goes through the scan below, and only those
  // compete against each other on priority for the scarce slots it finds.
  const flexibleTimed=events.filter(e=>e.time&&isReorderableTask(e));
  const flexibleTimeless=events.filter(e=>!e.time&&isReorderableTask(e))
    .sort((a,b)=>calculateTaskPriority(b,events)-calculateTaskPriority(a,events));

  // Weekly Routine occurrences for today are absolute shields, folded into
  // occupiedSlots right alongside real hard events. "Free period" occurrences
  // are tracked separately as preferred landing spots for short micro-tasks.
  const routineToday=getRoutineOccurrencesForDate(tk);
  const shieldOccurrences=routineToday.filter(r=>r.kind!=="free period");
  const freeWindows=routineToday.filter(r=>r.kind==="free period").map(r=>({start:timeToMinutes(r.time),end:timeToMinutes(r.time)+(r.duration||30)}));

  // Seeded with everything that already has a real, fixed span -- hard
  // events AND already-timed flexible tasks both have to block a timeless
  // item from landing on top of them.
  const occupiedSlots=[
    ...hardEvents.map(e=>({start:timeToMinutes(e.time),end:timeToMinutes(e.time)+(e.duration||30)+computeBreathingRoom(e.duration||30)})),
    ...flexibleTimed.map(e=>({start:timeToMinutes(e.time),end:timeToMinutes(e.time)+(e.duration||30)+computeBreathingRoom(e.duration||30)})),
    ...shieldOccurrences.map(r=>({start:timeToMinutes(r.time),end:timeToMinutes(r.time)+(r.duration||30)})),
  ];

  // Place genuinely timeless flexible tasks into whatever room is left,
  // highest-priority first.
  const placedTimeless=[];
  const unplacedTimeless=[];
  flexibleTimeless.forEach(task=>{
    const dur=task.duration||30;
    let placed=false;

    // Short tasks (flashcards/quick review, ≤20 min) preferentially land
    // inside a free-period/study-hall window before using the general peak
    // window — that's the "Dead Time Activation" the free periods exist for.
    if(dur<=20){
      for(const w of freeWindows){
        const wStart=Math.max(w.start,nowFloorMins);
        for(let timeSlot=wStart;timeSlot+dur<=w.end&&!placed;timeSlot+=15){
          if(!detectConflicts(task,occupiedSlots,timeSlot)){
            occupiedSlots.push({start:timeSlot,end:timeSlot+dur});
            placedTimeless.push({...task,time:minutesToTime(timeSlot)});
            placed=true;
          }
        }
        if(placed)break;
      }
    }

    // Try to find first available slot within work window
    if(!placed){
      for(let timeSlot=workStart;timeSlot+dur<=workEnd;timeSlot+=15){
        if(!detectConflicts(task,occupiedSlots,timeSlot)){
          occupiedSlots.push({start:timeSlot,end:timeSlot+dur});
          placedTimeless.push({...task,time:minutesToTime(timeSlot)});
          placed=true;
          break;
        }
      }
    }

    if(!placed){
      unplacedTimeless.push({...task,reason:"No available window within preferred hours"});
    }
  });

  // Every task with a real placement time -- hard events untouched, real
  // flexible sessions at their own committed time, timeless ones at
  // whatever slot was just found -- is eligible for chunking: a long
  // single sitting gets split into 45-min pieces with breaks purely for
  // display, never touching the real calendar event or its committed time.
  const chunked=chunkTasksWithBreaks([...flexibleTimed,...placedTimeless]);

  // Merge everything and sort by actual start time. Previously hard events
  // were pushed first and flexible ones appended after with no real sort --
  // that only ever looked right because the flexible bucket was always
  // empty (isFlexible was never set anywhere). Anything with no time (a
  // task that genuinely couldn't be placed anywhere today) sorts last.
  return [...hardEvents,...chunked,...unplacedTimeless]
    .map(t=>({...t,done:t.status==="done",scheduled:!!t.time}))
    .sort((a,b)=>{
      if(!a.time&&!b.time)return 0;
      if(!a.time)return 1;
      if(!b.time)return -1;
      return a.time<b.time?-1:a.time>b.time?1:0;
    });
}

function todaysPlan(){
  const events=lsGet("events",[]);
  return advancedSchedulePlanner(events);
}

// rearrangeUserTasks (a duplicate, raw-scale-priority version of
// calculateTaskPriority/advancedSchedulePlanner below) was removed here --
// confirmed zero callers anywhere in the file.


// Standalone versions of CalendarTab's own markDone/uncrossDone (which stay
// as thin wrappers around these, so its own callers are unaffected) --
// pulled out so Dashboard's Today's Plan checkbox can complete a task the
// exact same way Calendar's own click-to-toggle does, both writing the
// real ev.status everyone else already reads (Calendar's grid, Tier 0, XP/
// streak tracking). This replaces the old togglePlanDone/"planDone" shadow
// map, which only ever toggled a side localStorage key Dashboard alone
// read -- checking something off in Today's Plan never touched the real
// event, so Calendar (and everything else keyed off ev.status) still saw
// it as pending. planDone is fully retired, not just unused: its own two
// read sites (here and Dashboard's checkbox) are both gone now.
function markEventDone(id){
  const events=lsGet("events",[]);
  const target=events.find(ev=>ev.id===id);
  if(target&&target.time)logCompletionOutcome("done",target.time,difficultyTierOf(target));
  const next=events.map(ev=>{if(ev.id!==id)return ev;const {movedByStudlin,movedFrom,movedAt,...rest}=ev;return {...rest,status:"done",completedAt:Date.now()};});
  lsSet("events",next);
  return next;
}
function uncrossEventDone(id){
  const events=lsGet("events",[]);
  const next=events.map(ev=>ev.id===id?{...ev,status:"pending"}:ev);
  lsSet("events",next);
  return next;
}
function profileStats(){const s=lsGet("sessions",[]);const totalMin=s.reduce((a,x)=>a+(x.m||0),0);const st=sessionStats();return {totalMin,focusSessions:s.length,weekMin:st.weekMin,avg:st.avg};}
// No more manual Time Zone picker in Settings — always the browser's actual
// current zone, computed fresh rather than trusted from a possibly-stale
// stored value (e.g. a profile saved before a student traveled/moved).
function detectTz(){
  try{return Intl.DateTimeFormat().resolvedOptions().timeZone||"America/New_York";}catch(e){return "America/New_York";}
}
function getProfile(){
  try{
    const u=typeof firebase!=="undefined"?firebase.auth().currentUser:null;
    const def={name:(u&&u.displayName)||"Student",email:(u&&u.email)||"you@studlin.app",school:"",tz:detectTz(),status:"",affiliation:""};
    return {...lsGet("profile",def),tz:detectTz()};
  }catch(e){return{name:"Student",email:"you@studlin.app",school:"",tz:detectTz(),status:"",affiliation:""};}
}
function getUserPicUrl(){return lsGet("profilePic","");}
function getUserInitials(){
  try{
    const u=typeof firebase!=="undefined"?firebase.auth().currentUser:null;
    const n=(u&&u.displayName)||getProfile().name||"S";
    if(!n)return "S";
    const p=n.trim().split(" ").filter(Boolean);
    return p.length>1?(p[0][0]+p[p.length-1][0]).toUpperCase():n.slice(0,2).toUpperCase();
  }catch(e){return "S";}
}
function getUserName(){
  try{
    const u=typeof firebase!=="undefined"?firebase.auth().currentUser:null;
    return (u&&u.displayName)||getProfile().name||"Student";
  }catch(e){return "Student";}
}
function saveProfile(p){lsSet("profile",p);}
function seedEventsIfStale(){
  return;
  const ev=lsGet("events",null); const tk=dayKey();
  if(ev&&ev.some(e=>e.date>=tk))return;
  const mk=(off,time,title,subject,kind)=>{const d=new Date();d.setDate(d.getDate()+off);return {id:"seed-"+off+"-"+time,date:dayKey(d),time,title,subject,kind};};
  lsSet("events",[
    mk(0,"14:30","Chem quiz · Periodic trends","Chemistry","exam"),
    mk(0,"19:00","Macbeth essay · draft a section","English IV","study block"),
    mk(0,"21:00","Bio · cell respiration review","Biology","study block"),
    mk(1,"23:59","Biology lab report due","Biology","deadline"),
    mk(3,"09:00","Macbeth essay · first draft","English IV","deadline"),
    mk(5,"10:00","Calculus test · Derivatives","Calculus","exam"),
  ]);
}

// ─── SCHEDULE SETTINGS PANEL (Feature 2: Editable Preferences) ─────────────────
function ScheduleSettingsPanel({open,onClose,onSave}){
  const prefs=getSchedulePreferences();
  const [workStart,setWorkStart]=useState(prefs.workStartTime);
  const [workEnd,setWorkEnd]=useState(prefs.workEndTime);
  const [difficulty,setDifficulty]=useState(prefs.difficultyPreference);
  const [weekendEnabled,setWeekendEnabled]=useState(prefs.weekendEnabled);
  const [weekendStart,setWeekendStart]=useState(prefs.weekendStartTime);
  const [weekendEnd,setWeekendEnd]=useState(prefs.weekendEndTime);
  const [peakBuckets,setPeakBuckets]=useState(prefs.peakHourBuckets||[]);
  const togglePeakBucket=(id)=>setPeakBuckets(peakBuckets.includes(id)?peakBuckets.filter(b=>b!==id):[...peakBuckets,id]);
  const [saved,setSaved]=useState(false);

  // An end time at or before start time leaves the scheduler with a
  // zero-width or inverted window it can never actually place anything
  // in — findOpenSlotFor/findFixedEventSlot don't error on that, they
  // silently fall back to handing back whatever slot was asked for,
  // unchecked. Catching it here, before it's ever saved, is simpler and
  // safer than trying to make every downstream scheduling function defend
  // against a schedule that was never valid to begin with.
  const workHoursInvalid=timeToMinutes(workEnd)<=timeToMinutes(workStart);
  const weekendHoursInvalid=weekendEnabled&&timeToMinutes(weekendEnd)<=timeToMinutes(weekendStart);
  const canSave=!workHoursInvalid&&!weekendHoursInvalid;

  // A declared peak bucket only ever actually influences placement (see
  // findTier0Slot/findReliableSlotFor) when it overlaps the student's own
  // work-hours window at all — "Morning" (6-11am) or "Evening" (6-10pm)
  // against this app's own default 9am-6pm window has zero overlap, so
  // picking either did nothing and said nothing about why. Purely
  // informational (never blocks Save) — the student may genuinely want to
  // declare a preference now and widen their hours to match later.
  const unreachablePeakBuckets=!workHoursInvalid?TIER0_HOUR_BUCKETS.filter(b=>
    peakBuckets.includes(b.id)&&!(b.startMin<timeToMinutes(workEnd)&&b.endMin>timeToMinutes(workStart))
  ):[];

  const handleSave=()=>{
    if(!canSave)return;
    const newPrefs={
      ...prefs,
      workStartTime:workStart,
      workEndTime:workEnd,
      difficultyPreference:difficulty,
      weekendEnabled,
      weekendStartTime:weekendStart,
      weekendEndTime:weekendEnd,
      peakHourBuckets:peakBuckets,
    };
    setSchedulePreferences(newPrefs);
    setSaved(true);
    setTimeout(()=>setSaved(false),2000);
    if(onSave)onSave();
  };
  
  if(!open)return null;
  
  return (
    <div onClick={onClose} style={{position:"fixed",inset:0,zIndex:95,background:"rgba(8,12,10,0.72)",backdropFilter:"blur(7px)",display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div onClick={e=>e.stopPropagation()} style={{width:520,maxWidth:"100%",background:T.surface,border:"1px solid "+T.border,borderRadius:16,padding:28,boxShadow:"0 40px 90px -30px rgba(0,0,0,0.65)",maxHeight:"90vh",overflowY:"auto"}}>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:24}}>
          <span style={{display:"inline-flex",width:34,height:34,borderRadius:10,background:T.lime+"20",border:"1px solid "+T.lime+"44",alignItems:"center",justifyContent:"center",color:T.lime}}>{Icon.settings}</span>
          <div style={{fontSize:18,fontWeight:700,color:T.white,letterSpacing:"-0.01em"}}>Study Schedule Preferences</div>
        </div>
        
        <div style={{marginBottom:22}}>
          <label style={{display:"block",fontSize:11,fontWeight:700,letterSpacing:"0.08em",textTransform:"uppercase",color:T.muted,marginBottom:8}}>Work Hours</label>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
            <div>
              <label style={{fontSize:12,color:T.text,marginBottom:4,display:"block"}}>Start time</label>
              <TimeInput value={workStart} onChange={setWorkStart} style={{fontFamily:T.mono}} />
            </div>
            <div>
              <label style={{fontSize:12,color:T.text,marginBottom:4,display:"block"}}>End time</label>
              <TimeInput value={workEnd} onChange={setWorkEnd} style={{fontFamily:T.mono}} />
            </div>
          </div>
          {workHoursInvalid
            ?<div style={{fontSize:11.5,color:T.red,marginTop:6}}>End time must be after start time.</div>
            :<div style={{fontSize:11,color:T.muted,marginTop:6,lineHeight:1.4}}>Tasks will be scheduled within this window. Your study schedule respects these hours.</div>}
        </div>

        <div style={{marginBottom:22}}>
          <div onClick={()=>setWeekendEnabled(!weekendEnabled)} style={{display:"flex",alignItems:"center",justifyContent:"space-between",cursor:"pointer",marginBottom:weekendEnabled?12:0}}>
            <label style={{fontSize:11,fontWeight:700,letterSpacing:"0.08em",textTransform:"uppercase",color:T.muted,cursor:"pointer"}}>Different Weekend Hours</label>
            <div style={{width:34,height:19,borderRadius:99,background:weekendEnabled?T.lime:T.card2,border:"1px solid "+(weekendEnabled?T.lime:T.border),position:"relative",transition:"all 0.15s",flexShrink:0}}>
              <div style={{position:"absolute",top:1,left:weekendEnabled?16:1,width:15,height:15,borderRadius:"50%",background:weekendEnabled?T.ink:T.muted,transition:"all 0.15s"}}/>
            </div>
          </div>
          {weekendEnabled&&(
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
              <div>
                <label style={{fontSize:12,color:T.text,marginBottom:4,display:"block"}}>Sat/Sun start</label>
                <TimeInput value={weekendStart} onChange={setWeekendStart} style={{fontFamily:T.mono}} />
              </div>
              <div>
                <label style={{fontSize:12,color:T.text,marginBottom:4,display:"block"}}>Sat/Sun end</label>
                <TimeInput value={weekendEnd} onChange={setWeekendEnd} style={{fontFamily:T.mono}} />
              </div>
            </div>
          )}
          {weekendHoursInvalid
            ?<div style={{fontSize:11.5,color:T.red,marginTop:6}}>End time must be after start time.</div>
            :<div style={{fontSize:11,color:T.muted,marginTop:6,lineHeight:1.4}}>{weekendEnabled?"Weekends will use this window instead of your weekday hours.":"Off — weekends use the same hours as weekdays."}</div>}
        </div>

        <div style={{marginBottom:22}}>
          <label style={{display:"block",fontSize:11,fontWeight:700,letterSpacing:"0.08em",textTransform:"uppercase",color:T.muted,marginBottom:8}}>Difficulty Preference</label>
          <div style={{display:"flex",gap:8}}>
            {[
              {value:"easyFirst",label:"Easy First",desc:"Tackle quick wins before hard tasks"},
              {value:"balanced",label:"Balanced",desc:"Mix easy and hard throughout"},
              {value:"hardFirst",label:"Hard First",desc:"Hit hard tasks during peak focus"},
            ].map(opt=>(
              <button
                key={opt.value}
                onClick={()=>setDifficulty(opt.value)}
                style={{
                  flex:1,padding:12,borderRadius:8,border:"1px solid "+(difficulty===opt.value?T.lime+"66":T.border),
                  background:difficulty===opt.value?T.lime+"14":"transparent",
                  color:difficulty===opt.value?T.lime:T.muted,
                  fontSize:12,fontWeight:difficulty===opt.value?600:500,
                  cursor:"pointer",
                  transition:"all 0.15s",
                  textAlign:"left",
                }}
              >
                <div style={{fontWeight:600}}>{opt.label}</div>
                <div style={{fontSize:10.5,opacity:0.8,marginTop:2}}>{opt.desc}</div>
              </button>
            ))}
          </div>
        </div>

        <div style={{marginBottom:22}}>
          <label style={{display:"block",fontSize:11,fontWeight:700,letterSpacing:"0.08em",textTransform:"uppercase",color:T.muted,marginBottom:8}}>
            Peak Focus Hours <span style={{textTransform:"none",fontWeight:400,color:T.faint}}>(optional)</span>
          </label>
          <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
            {TIER0_HOUR_BUCKETS.map(b=>(
              <button key={b.id} type="button" onClick={()=>togglePeakBucket(b.id)} style={peakChipStyle(peakBuckets.includes(b.id))}>
                {PEAK_BUCKET_LABELS[b.id]}
                <span style={{opacity:0.7,marginLeft:4}}>{fmtClock12(minutesToTime(b.startMin))}–{fmtClock12(minutesToTime(b.endMin))}</span>
              </button>
            ))}
          </div>
          <div style={{fontSize:11,color:T.muted,marginTop:6,lineHeight:1.4}}>Studlin prefers these times when rescheduling missed tasks. Pick 1-2 for the strongest effect. Leave blank and Studlin will learn your best hours from your habits over time.</div>
          {unreachablePeakBuckets.length>0&&(
            <div style={{fontSize:11.5,color:T.amber,marginTop:8,lineHeight:1.4}}>
              {unreachablePeakBuckets.map(b=>PEAK_BUCKET_LABELS[b.id]).join(" and ")} {unreachablePeakBuckets.length>1?"don't":"doesn't"} overlap your Work Hours ({fmtClock12(workStart)}–{fmtClock12(workEnd)}) at all, so Studlin can't actually place anything there yet — widen your Work Hours above to cover it.
            </div>
          )}
        </div>

        {saved&&<div style={{background:T.lime+"20",border:"1px solid "+T.lime+"44",borderRadius:8,padding:12,fontSize:12,color:T.lime,marginBottom:16,display:"flex",alignItems:"center",gap:8}}>
          <span style={{display:"inline-flex"}}>✓</span>
          Preferences saved! Your schedule will instantly re-sort.
        </div>}
        
        <div style={{display:"flex",gap:10,justifyContent:"flex-end"}}>
          <button onClick={onClose} style={{padding:"10px 18px",borderRadius:8,border:"1px solid "+T.border,background:"transparent",color:T.muted,fontSize:12.5,fontWeight:600,cursor:"pointer",fontFamily:T.font}}>Cancel</button>
          <button onClick={handleSave} disabled={!canSave} style={{padding:"10px 18px",borderRadius:8,border:"none",background:T.lime,color:T.ink,fontSize:12.5,fontWeight:600,cursor:canSave?"pointer":"not-allowed",fontFamily:T.font,opacity:canSave?1:0.45}}>Save Preferences</button>
        </div>
      </div>
    </div>
  );
}

// ─── UPGRADE MODAL (shared paywall) ───────────────────────────────────────────
function UpgradeModal({open,onClose,feature,detail,onUpgraded}){
  if(!open)return null;
  const tiers=[
    {name:"Pro",price:"$9.99",perks:["Unlimited AI chat, scans & flashcard generation","Every AI model + 4 study modes","Unlimited decks + notes scanning"],color:T.lime},
    {name:"Max",price:"$24.99",perks:["Everything in Pro, completely unlimited","Priority AI: faster, no queue","Advanced analytics + learning paths"],color:T.purple},
  ];
  const choose=(name)=>{setPlanLS(name);onClose();if(onUpgraded)onUpgraded(name);};
  return (
    <div onClick={onClose} style={{position:"fixed",inset:0,zIndex:90,background:"rgba(8,12,10,0.72)",backdropFilter:"blur(7px)",display:"flex",alignItems:"center",justifyContent:"center"}}>
      <div onClick={e=>e.stopPropagation()} style={{width:580,maxWidth:"92vw",background:T.surface,border:"1px solid "+T.border,borderRadius:16,padding:28,boxShadow:"0 40px 90px -30px rgba(0,0,0,0.65)"}}>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:6}}>
          <span style={{display:"inline-flex",width:30,height:30,borderRadius:8,background:T.lime+"1c",border:"1px solid "+T.lime+"44",alignItems:"center",justifyContent:"center",color:T.lime}}>{Icon.wand}</span>
          <div style={{fontSize:17,fontWeight:700,color:T.white,letterSpacing:"-0.01em"}}>You have hit your {feature} limit</div>
        </div>
        <div style={{fontSize:12.5,color:T.text,lineHeight:1.6,marginBottom:18}}>{detail}</div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:14}}>
          {tiers.map(t=>(
            <div key={t.name} style={{background:T.card,border:"1px solid "+(t.name==="Max"?t.color+"55":T.border),borderRadius:12,padding:16,position:"relative"}}>
              {t.name==="Max"&&<span style={{position:"absolute",top:-8,right:12,fontSize:9,fontWeight:700,letterSpacing:"0.08em",background:t.color,color:"#fff",padding:"2px 8px",borderRadius:4}}>BEST VALUE</span>}
              <div style={{fontSize:13,fontWeight:700,color:t.color,marginBottom:2}}>{t.name}</div>
              <div style={{fontSize:24,fontWeight:700,color:T.white,letterSpacing:"-0.02em"}}>{t.price}<span style={{fontSize:11,color:T.muted,fontWeight:400}}> /month</span></div>
              <div style={{margin:"10px 0 14px"}}>
                {t.perks.map((p,i)=>(
                  <div key={i} style={{display:"flex",gap:7,alignItems:"center",fontSize:11.5,color:T.text,padding:"3px 0"}}><span style={{color:t.color,display:"inline-flex"}}>{Icon.check}</span>{p}</div>
                ))}
              </div>
              <Btn onClick={()=>choose(t.name)} style={{width:"100%",justifyContent:"center",background:t.name==="Max"?t.color:T.lime,color:t.name==="Max"?"#fff":T.ink}}>Upgrade to {t.name}</Btn>
            </div>
          ))}
        </div>
        <div onClick={onClose} style={{textAlign:"center",fontSize:12,color:T.muted,cursor:"pointer",padding:6}}>Maybe later</div>
      </div>
    </div>
  );
}

